export interface CronResult {
  readonly minute: readonly number[];
  readonly hour: readonly number[];
  readonly dayOfMonth: readonly number[];
  readonly month: readonly number[];
  readonly dayOfWeek: readonly number[];
}

interface FieldConfig {
  readonly name: string;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = Object.freeze([
  Object.freeze({ name: "minute",     min: 0, max: 59 }),
  Object.freeze({ name: "hour",       min: 0, max: 23 }),
  Object.freeze({ name: "dayOfMonth", min: 1, max: 31 }),
  Object.freeze({ name: "month",      min: 1, max: 12 }),
  Object.freeze({ name: "dayOfWeek",  min: 0, max: 6  }),
]);

function assertSafeInteger(raw: string, fieldName: string): number {
  if (typeof raw !== "string") {
    throw new TypeError(`parseCron: '${fieldName}' numeric token must be a string, got ${typeof raw}`);
  }
  const trimmed = raw.trim();
  if (trimmed === "") {
    throw new TypeError(`parseCron: '${fieldName}' contains an empty numeric token`);
  }
  if (!/^\d+$/.test(trimmed)) {
    throw new TypeError(`parseCron: '${fieldName}' token '${trimmed}' is not a non-negative integer`);
  }
  const val = Number(trimmed);
  if (!Number.isSafeInteger(val)) {
    throw new TypeError(`parseCron: '${fieldName}' token '${trimmed}' overflows safe integer range`);
  }
  return val;
}

function assertInRange(val: number, min: number, max: number, fieldName: string, context: string): void {
  if (val < min || val > max) {
    throw new TypeError(
      `parseCron: '${fieldName}' ${context} value ${val} is out of valid range [${min}, ${max}]`
    );
  }
}

function expandRange(expression: string, config: FieldConfig): number[] {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new TypeError(`parseCron: '${config.name}' received invalid range expression`);
  }

  const dashIdx = expression.indexOf("-");
  if (dashIdx <= 0) {
    throw new TypeError(`parseCron: '${config.name}' range '${expression}' missing start before '-'`);
  }

  const leftRaw  = expression.slice(0, dashIdx);
  const rightRaw = expression.slice(dashIdx + 1);

  if (rightRaw === "" || rightRaw.includes("-")) {
    throw new TypeError(`parseCron: '${config.name}' range '${expression}' has malformed end`);
  }

  const start = assertSafeInteger(leftRaw,  config.name);
  const end   = assertSafeInteger(rightRaw, config.name);

  assertInRange(start, config.min, config.max, config.name, "range start");
  assertInRange(end,   config.min, config.max, config.name, "range end");

  if (start > end) {
    throw new TypeError(
      `parseCron: '${config.name}' range start ${start} must not exceed end ${end}`
    );
  }

  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function expandWildcard(config: FieldConfig): number[] {
  const result: number[] = [];
  for (let i = config.min; i <= config.max; i++) result.push(i);
  return result;
}

function expandStep(expression: string, config: FieldConfig): number[] {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron: '${config.name}' step expression must be a string`);
  }

  const slashIdx = expression.indexOf("/");
  if (slashIdx < 1) {
    throw new TypeError(`parseCron: '${config.name}' step '${expression}' missing base before '/'`);
  }
  if (expression.indexOf("/", slashIdx + 1) !== -1) {
    throw new TypeError(`parseCron: '${config.name}' step '${expression}' contains multiple '/' operators`);
  }

  const baseRaw = expression.slice(0, slashIdx);
  const stepRaw = expression.slice(slashIdx + 1);

  if (stepRaw === "") {
    throw new TypeError(`parseCron: '${config.name}' step '${expression}' missing value after '/'`);
  }

  const step = assertSafeInteger(stepRaw, config.name);
  if (step < 1) {
    throw new TypeError(`parseCron: '${config.name}' step value must be >= 1, got ${step}`);
  }

  let rangeMin: number;
  let rangeMax: number;

  if (baseRaw === "*") {
    rangeMin = config.min;
    rangeMax = config.max;
  } else if (baseRaw.includes("-")) {
    const expanded = expandRange(baseRaw, config);
    if (expanded.length === 0) {
      throw new TypeError(`parseCron: '${config.name}' step base range '${baseRaw}' expanded to nothing`);
    }
    rangeMin = expanded[0]!;
    rangeMax = expanded[expanded.length - 1]!;
  } else {
    const val = assertSafeInteger(baseRaw, config.name);
    assertInRange(val, config.min, config.max, config.name, "step base");
    rangeMin = val;
    rangeMax = config.max;
  }

  const result: number[] = [];
  for (let i = rangeMin; i <= rangeMax; i += step) result.push(i);

  if (result.length === 0) {
    throw new TypeError(
      `parseCron: '${config.name}' step expression '${expression}' produced no values`
    );
  }

  return result;
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (typeof raw !== "string") {
    throw new TypeError(`parseCron: field '${config.name}' token must be a string, got ${typeof raw}`);
  }
  if (raw.trim() === "") {
    throw new TypeError(`parseCron: field '${config.name}' token must not be empty`);
  }

  if (raw.includes(",")) {
    const parts = raw.split(",");
    if (parts.length < 2) {
      throw new TypeError(`parseCron: '${config.name}' comma list '${raw}' has fewer than 2 elements`);
    }
    const seen = new Set<number>();
    for (const part of parts) {
      if (part.trim() === "") {
        throw new TypeError(`parseCron: '${config.name}' comma list '${raw}' contains an empty element`);
      }
      if (part.includes(",")) {
        throw new TypeError(`parseCron: '${config.name}' comma list '${raw}' contains nested commas`);
      }
      for (const v of parseField(part.trim(), config)) {
        seen.add(v);
      }
    }
    if (seen.size === 0) {
      throw new TypeError(`parseCron: '${config.name}' comma list '${raw}' resolved to no values`);
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  if (raw.includes("/")) return expandStep(raw, config);
  if (raw === "*")        return expandWildcard(config);
  if (raw.includes("-"))  return expandRange(raw, config);

  const val = assertSafeInteger(raw, config.name);
  assertInRange(val, config.min, config.max, config.name, "literal");
  return [val];
}

export default function parseCron(expression: unknown): CronResult {
  if (expression === null || expression === undefined) {
    throw new TypeError(`parseCron: expression must be a non-empty string, got ${expression}`);
  }
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron: expression must be a string, got ${typeof expression}`);
  }
  if (expression.trim() === "") {
    throw new TypeError("parseCron: expression must not be empty or purely whitespace");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new TypeError(
      `parseCron: expression must have exactly 5 whitespace-separated fields, got ${fields.length}`
    );
  }

  const parsed = Object.create(null) as {
    minute?: number[];
    hour?: number[];
    dayOfMonth?: number[];
    month?: number[];
    dayOfWeek?: number[];
  };

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    if (config == null) {
      throw new TypeError(`parseCron: internal — field config at index ${i} is unexpectedly nullish`);
    }
    const rawField = fields[i];
    if (rawField == null) {
      throw new TypeError(`parseCron: internal — field token at index ${i} is unexpectedly nullish`);
    }

    const values = parseField(rawField, config);

    if (!Array.isArray(values) || values.length === 0) {
      throw new TypeError(`parseCron: field '${config.name}' resolved to an empty or invalid array`);
    }

    (parsed as Record<string, number[]>)[config.name] = Object.freeze(values) as number[];
  }

  const REQUIRED_KEYS = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;
  for (const key of REQUIRED_KEYS) {
    if (!Array.isArray(parsed[key]) || (parsed[key] as number[]).length === 0) {
      throw new TypeError(`parseCron: post-parse integrity check failed for field '${key}'`);
    }
  }

  const result = Object.create(null) as CronResult;
  (result as { minute: number[] }).minute     = parsed.minute!;
  (result as { hour: number[] }).hour         = parsed.hour!;
  (result as { dayOfMonth: number[] }).dayOfMonth = parsed.dayOfMonth!;
  (result as { month: number[] }).month       = parsed.month!;
  (result as { dayOfWeek: number[] }).dayOfWeek = parsed.dayOfWeek!;

  return Object.freeze(result);
}
