interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(expr: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of expr.split(",")) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    if (trimmed.startsWith("*/")) {
      const step = parseInt(trimmed.slice(2), 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: "${trimmed}"`);
      }
      for (let i = min; i <= max; i += step) results.add(i);
      continue;
    }

    if (trimmed.includes("/")) {
      const [rangePart, stepPart] = trimmed.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: "${trimmed}"`);
      }
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        const start = parseInt(startStr, 10);
        const end = parseInt(endStr, 10);
        if (isNaN(start) || isNaN(end)) {
          throw new Error(`Invalid range: "${rangePart}"`);
        }
        validateRange(start, end, min, max, trimmed);
        for (let i = start; i <= end; i += step) results.add(i);
      } else {
        const start = parseInt(rangePart, 10);
        if (isNaN(start)) {
          throw new Error(`Invalid value: "${trimmed}"`);
        }
        validateValue(start, min, max, trimmed);
        for (let i = start; i <= max; i += step) results.add(i);
      }
      continue;
    }

    if (trimmed.includes("-")) {
      const [startStr, endStr] = trimmed.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Invalid range: "${trimmed}"`);
      }
      validateRange(start, end, min, max, trimmed);
      for (let i = start; i <= end; i++) results.add(i);
      continue;
    }

    const value = parseInt(trimmed, 10);
    if (isNaN(value)) {
      throw new Error(`Invalid cron value: "${trimmed}"`);
    }
    validateValue(value, min, max, trimmed);
    results.add(value);
  }

  return Array.from(results).sort((a, b) => a - b);
}

function validateValue(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of range [${min}-${max}] in expression: "${context}"`
    );
  }
}

function validateRange(
  start: number,
  end: number,
  min: number,
  max: number,
  context: string
): void {
  if (start > end) {
    throw new Error(`Range start exceeds end in expression: "${context}"`);
  }
  validateValue(start, min, max, context);
  validateValue(end, min, max, context);
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  const [minute, hour, dayOfMonth, month, dayOfWeek] = [
    minuteExpr,
    hourExpr,
    dayOfMonthExpr,
    monthExpr,
    dayOfWeekExpr,
  ].map((expr, i) => {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    try {
      return parseField(expr, min, max);
    } catch (err) {
      throw new Error(
        `Error in ${name} field ("${expr}"): ${(err as Error).message}`
      );
    }
  });

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseNumber(token: string, min: number, max: number): number {
  const n = parseInt(token, 10);
  if (isNaN(n) || String(n) !== token.trim()) {
    throw new SyntaxError(`Invalid number: "${token}"`);
  }
  return clamp(n, min, max);
}

function expandRange(start: number, end: number): number[] {
  if (start > end) {
    throw new RangeError(`Invalid range: ${start}-${end}`);
  }
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */step or start-end/step
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    if (!stepPart || stepPart === "") {
      throw new SyntaxError(`Invalid step expression: "${segment}"`);
    }
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value: "${stepPart}"`);
    }

    let rangeStart = min;
    let rangeEnd = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-");
        rangeStart = parseNumber(s, min, max);
        rangeEnd = parseNumber(e, min, max);
      } else {
        rangeStart = parseNumber(rangePart, min, max);
      }
    }

    const result: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      result.push(i);
    }
    return result;
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range expression: "${segment}"`);
    }
    const start = parseNumber(parts[0], min, max);
    const end = parseNumber(parts[1], min, max);
    return expandRange(start, end);
  }

  // Single number
  return [parseNumber(segment, min, max)];
}

function parseField(field: string, min: number, max: number): number[] {
  const segments = field.split(",");
  if (segments.length === 0) {
    throw new SyntaxError(`Empty field`);
  }

  const values = new Set<number>();
  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) {
      throw new SyntaxError(`Empty segment in field: "${field}"`);
    }
    for (const v of parseSegment(trimmed, min, max)) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

function normalizeDayOfWeek(values: number[]): number[] {
  // Treat 7 as equivalent to 0 (Sunday)
  const normalized = new Set<number>();
  for (const v of values) {
    normalized.add(v === 7 ? 0 : v);
  }
  return Array.from(normalized).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (!expression || typeof expression !== "string") {
    throw new TypeError("Expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = parts;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const [minuteRange, hourRange, domRange, monthRange, dowRange] =
    fieldNames.map((f) => FIELD_RANGES[f]);

  const minute = parseField(minuteStr, minuteRange.min, minuteRange.max);
  const hour = parseField(hourStr, hourRange.min, hourRange.max);
  const dayOfMonth = parseField(domStr, domRange.min, domRange.max);
  const month = parseField(monthStr, monthRange.min, monthRange.max);
  const dayOfWeek = normalizeDayOfWeek(
    parseField(dowStr, dowRange.min, dowRange.max)
  );

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

// Debounce: delay execution until calls stop arriving for `delayMs`.
// The returned function has .cancel() and .flush() to give callers
// explicit control — useful for cleanup on unmount or save-on-blur.

type AnyFunction = (...args: Parameters<AnyFunction>) => ReturnType<AnyFunction>;

// We use a generic constraint so callers get back the original
// argument and return types, not a widened `any` signature.
type DebouncedFunction<F extends AnyFunction> = {
  (...args: Parameters<F>): void;
  cancel: () => void;
  flush: () => void;
};

function debounce<F extends AnyFunction>(fn: F, delayMs: number): DebouncedFunction<F> {
  // Timer handle — null means nothing is pending
  let timerId: ReturnType<typeof setTimeout> | null = null;

  // Hold onto the most recent args so flush() can replay them
  let pendingArgs: Parameters<F> | null = null;

  // Core: reset the timer on every call so only the trailing
  // edge fires — the classic debounce contract.
  const debounced = (...args: Parameters<F>): void => {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      // Timer fired naturally — execute and clean up
      timerId = null;
      const argsToCall = pendingArgs;
      pendingArgs = null;

      if (argsToCall !== null) {
        fn(...argsToCall);
      }
    }, delayMs);
  };

  // cancel: drop the pending call without executing it.
  // Safe to call even when nothing is pending.
  debounced.cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  // flush: fire immediately if a call is waiting.
  // Clears the timer first so the scheduled call doesn't also fire.
  debounced.flush = (): void => {
    if (timerId === null) {
      // Nothing pending — nothing to flush
      return;
    }

    clearTimeout(timerId);
    timerId = null;

    const argsToCall = pendingArgs;
    pendingArgs = null;

    if (argsToCall !== null) {
      fn(...argsToCall);
    }
  };

  return debounced;
}

export default debounce;
