// @stance: minimal

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || value === undefined) return false;
  if (typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  if (proto !== null && proto !== Object.prototype) return false;
  return true;
}

function assertValidKey(key: string, path: string): void {
  if (typeof key !== "string") {
    throw new TypeError(
      `flattenObject: encountered non-string key at path "${path}"; got ${typeof key}`
    );
  }
  if (key.length === 0) {
    throw new TypeError(
      `flattenObject: encountered empty string key at path "${path}"; empty keys produce ambiguous dot-notation paths`
    );
  }
  if (key.includes("\0")) {
    throw new TypeError(
      `flattenObject: key at path "${path}" contains null byte — refusing to process`
    );
  }
}

function recurse(
  input: unknown,
  prefix: string,
  depth: number,
  maxDepth: number,
  result: FlatObject
): void {
  if (depth > maxDepth) {
    throw new RangeError(
      `flattenObject: exceeded maximum recursion depth of ${maxDepth} at path "${prefix}"; possible circular reference or pathologically deep structure`
    );
  }

  if (!isPlainObject(input)) {
    if (prefix === "") {
      throw new TypeError(
        `flattenObject: root value must be a plain object; got ${
          input === null ? "null" : Array.isArray(input) ? "array" : typeof input
        }`
      );
    }
    result[prefix] = input as Primitive | unknown[];
    return;
  }

  const keys = Object.keys(input as object);

  if (keys.length === 0) {
    if (prefix !== "") {
      result[prefix] = {};
    }
    return;
  }

  for (const key of keys) {
    assertValidKey(key, prefix === "" ? key : `${prefix}.${key}`);

    const nextPrefix = prefix === "" ? key : `${prefix}.${key}`;
    const child = (input as Record<string, unknown>)[key];

    if (child !== null && typeof child === "object" && !Array.isArray(child)) {
      const seenProto = Object.getPrototypeOf(child);
      if (seenProto !== null && seenProto !== Object.prototype) {
        result[nextPrefix] = child as unknown as Primitive;
        continue;
      }
    }

    recurse(child, nextPrefix, depth + 1, maxDepth, result);
  }
}

export function flattenObject(
  input: unknown,
  options?: { maxDepth?: number }
): FlatObject {
  if (input === null || input === undefined) {
    throw new TypeError(
      `flattenObject: input must be a non-null plain object; got ${input === null ? "null" : "undefined"}`
    );
  }

  if (typeof input !== "object") {
    throw new TypeError(
      `flattenObject: input must be a plain object; got ${typeof input}`
    );
  }

  if (Array.isArray(input)) {
    throw new TypeError(
      `flattenObject: input must be a plain object, not an array; wrap arrays in an object if intentional`
    );
  }

  if (options !== undefined && (typeof options !== "object" || Array.isArray(options) || options === null)) {
    throw new TypeError(
      `flattenObject: options must be a plain object if provided; got ${options === null ? "null" : typeof options}`
    );
  }

  const rawMaxDepth = options?.maxDepth;

  if (rawMaxDepth !== undefined) {
