// Defines the shape of a successfully parsed cron expression.
// Each field expands to the concrete list of integers it represents.
export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

// Valid inclusive ranges for each cron field.
// Keeping these as named constants so the constraint is self-documenting.
const FIELD_RANGES: Record<keyof ParsedCron, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 0 and 7 both mean Sunday (standard cron)
};

// Generates an inclusive integer sequence: range(1, 4) => [1, 2, 3, 4]
function range(from: number, to: number): number[] {
  if (from > to) {
    throw new Error(`Invalid range: ${from} is greater than ${to}`);
  }
  const result: number[] = [];
  for (let i = from; i <= to; i++) {
    result.push(i);
  }
  return result;
}

// Removes duplicates and sorts ascending.
// Used to keep the output arrays predictable regardless of input order.
function deduplicateAndSort(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

// Validates that every value in a list falls within [min, max].
// Throws a descriptive error so the caller can surface it to the user.
function assertInRange(
  values: number[],
  min: number,
  max: number,
  fieldName: string
): void {
  for (const v of values) {
    if (v < min || v > max) {
      throw new Error(
        `Field "${fieldName}": value ${v} is out of allowed range [${min}, ${max}]`
      );
    }
  }
}

// Parses a single cron token (one comma-separated segment) into numbers.
// Handles: plain number "5", wildcard "*", step "*/15" or "0-59/15", range "1-5".
function parseToken(
  token: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  // Step value: either "*/step" or "start-end/step"
  if (token.includes("/")) {
    const [rangePart, stepPart] = token.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(
        `Field "${fieldName}": step value "${stepPart}" must be a positive integer`
      );
    }

    // Determine the start/end of the range to step over
    let from = min;
    let to = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        from = parseInt(startStr, 10);
        to   = parseInt(endStr,   10);
        if (isNaN(from) || isNaN(to)) {
          throw new Error(
            `Field "${fieldName}": invalid range "${rangePart}" in step expression`
          );
        }
      } else {
        // "5/15" means start at 5, step to max
        from = parseInt(rangePart, 10);
        if (isNaN(from)) {
          throw new Error(
            `Field "${fieldName}": invalid start value "${rangePart}" in step expression`
          );
        }
      }
    }

    // Collect every value from `from` to `to` that is divisible by step offset
    const values: number[] = [];
    for (let i = from; i <= to; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: "1-5"
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const from = parseInt(startStr, 10);
    const to   = parseInt(endStr,   10);

    if (isNaN(from) || isNaN(to)) {
      throw new Error(
        `Field "${fieldName}": invalid range "${token}"`
      );
    }

    return range(from, to);
  }

  // Wildcard: "*"
  if (token === "*") {
    return range(min, max);
  }

  // Plain integer: "5"
  const value = parseInt(token, 10);
  if (isNaN(value)) {
    throw new Error(
      `Field "${fieldName}": "${token}" is not a valid cron token`
    );
  }

  return [value];
}

// Parses a full cron field string (may contain commas) into an array of numbers.
// Comma-separated lists like "1,3,5" are split and each segment parsed independently.
function parseField(
  fieldStr: string,
  fieldName: string,
  min: number,
  max: number
): number[] {
  // Split on commas so "1,3,5" and "1-3,5,*/10" all work correctly
  const segments = fieldStr.split(",");
  const collected: number[] = [];

  for (const segment of segments) {
    const values = parseToken(segment.trim(), min, max, fieldName);
    collected.push(...values);
  }

  const result = deduplicateAndSort(collected);

  // Validate after expansion — catches things like "60" in minutes
  assertInRange(result, min, max, fieldName);

  return result;
}

// Parses a 5-field cron expression string into a structured object.
// Throws descriptive errors for malformed input so callers can show useful messages.
export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("parseCron: expression must be a non-empty string");
  }

  // Split on whitespace; standard cron has exactly 5 fields
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `parseCron: expected 5 fields but got ${fields.length} in "${expression}"`
    );
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;

  // Parse each field against its known range
  const minute     = parseField(minuteStr, "minute",     FIELD_RANGES.minute.min,     FIELD_RANGES.minute.max);
  const hour       = parseField(hourStr,   "hour",       FIELD_RANGES.hour.min,       FIELD_RANGES.hour.max);
  const dayOfMonth = parseField(domStr,    "dayOfMonth", FIELD_RANGES.dayOfMonth.min, FIELD_RANGES.dayOfMonth.max);
  const month      = parseField(monthStr,  "month",      FIELD_RANGES.month.min,      FIELD_RANGES.month.max);
  const dayOfWeek  = parseField(dowStr,    "dayOfWeek",  FIELD_RANGES.dayOfWeek.min,  FIELD_RANGES.dayOfWeek.max);

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}
