// Type alias for a plain object — keeps signatures readable
type PlainObject = Record<string, unknown>;

// Returns true only for plain {} objects, not arrays, nulls, or class instances.
// We check the prototype explicitly so that things like `new Date()` or `new Map()`
// are treated as scalar values and get overwritten, not merged.
function isPlainObject(value: unknown): value is PlainObject {
  if (typeof value !== "object" || value === null) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

// Recursively merges `source` into a *copy* of `target`.
// We never mutate the inputs — callers at 3am shouldn't have to worry about that.
function deepMerge(target: PlainObject, source: PlainObject): PlainObject {
  // Start with a shallow copy of target so we don't clobber the original
  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      // Both sides are arrays → concatenate (spec requirement)
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      // Both sides are plain objects → recurse so nested keys get the same treatment
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      // Everything else (primitives, class instances, mismatched types) →
      // source wins, which is the standard merge contract
      result[key] = sourceVal;
    }
  }

  return result;
}

