type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type FlattenedObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;

  const proto = Object.getPrototypeOf(value);
  if (proto !== null && proto !== Object.prototype) return false;

  return true;
}

function flattenObject(
  input: unknown,
  prefix: string = "",
  depth: number = 0
): FlattenedObject {
  if (input === null || input === undefined) {
    throw new TypeError(
      `flattenObject: input must be a plain object, received ${input}`
    );
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject: input must be a plain object, received ${typeof input}`
    );
  }

  if (typeof prefix !== "string") {
    throw new TypeError(
      `flattenObject: prefix must be a string, received ${typeof prefix}`
    );
  }

  if (typeof depth !== "number" || !Number.isFinite(depth)) {
    throw new TypeError(
      `flattenObject: depth must be a finite number, received ${depth}`
    );
  }

  const MAX_DEPTH = 64;
  if (depth > MAX_DEPTH) {
    throw new RangeError(
      `flattenObject: exceeded maximum nesting depth of ${MAX_DEPTH}. Possible circular reference or excessively nested structure.`
    );
  }

  const result: FlattenedObject = Object.create(null);

  const keys = Object.keys(input);

  for (const key of keys) {
    if (typeof key !== "string") continue;

    if (key.length === 0) {
      throw new TypeError(
        `flattenObject: empty string keys are not permitted`
      );
    }

    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value: unknown = (input as Record<string, unknown>)[key];

    if (isPlainObject(value)) {
      const nested = flattenObject(value, fullKey, depth + 1);
      const nestedKeys = Object.keys(nested);

      if (nestedKeys.length === 0) {
        // empty nested object — preserve as empty marker? safest: skip.
        continue;
      }

      for (const nestedKey of nestedKeys) {
        if (Object.prototype.hasOwnProperty.call(result, nestedKey)) {
          throw new Error(
            `flattenObject: key collision detected at "${nestedKey}". Refusing to silently overwrite.`
          );
        }
        result[nestedKey] = nested[nestedKey];
      }
    } else if (Array.isArray(value)) {
      throw new TypeError(
        `flattenObject: arrays are not supported. Found array at key "${fullKey}". Coerce arrays before passing.`
      );
    } else {
      if (Object.prototype.hasOwnProperty.call(result, fullKey)) {
        throw new Error(
          `flattenObject: key collision detected at "${fullKey}". Refusing to silently overwrite.`
        );
      }
      result[fullKey] = value as Primitive;
    }
  }

  return result;
}

