const RANGES = { minute:[0,59], hour:[0,23], dayOfMonth:[1,31], month:[1,12], dayOfWeek:[0,6] } as const
type Field = keyof typeof RANGES

const expand = (expr: string, [min, max]: readonly [number, number]): number[] => {
  if (expr === '*') return Array.from({length: max-min+1}, (_,i) => i+min)
  if (expr.includes(',')) return [...new Set(expr.split(',').flatMap(e => expand(e, [min,max])))]
  if (expr.startsWith('*/')) {
    const step = +expr.slice(2)
    return Array.from({length: max-min+1}, (_,i) => i+min).filter(n => (n-min) % step === 0)
  }
  if (expr.includes('-')) {
    const [a,b] = expr.split('-').map(Number)
    return Array.from({length: b-a+1}, (_,i) => i+a)
  }
  const n = +expr
  if (n < min || n > max) throw new RangeError(`${n} out of [${min},${max}]`)
  return [n]
}

const parseCron = (cron: string): Record<Field, number[]> => {
  const parts = cron.trim().split(/\s+/)
  if (parts.length !== 5) throw new Error('Expected 5 fields')
  const keys = Object.keys(RANGES) as Field[]
  return Object.fromEntries(keys.map((k,i) => [k, expand(parts[i], RANGES[k])])) as Record<Field, number[]>
}

export default parseCron
