  let pendingArgs: Parameters<F> | null = null;
  let hasPending = false;

  const stateGuard = Object.create(null) as {
    timerId: ReturnType<typeof setTimeout> | null;
    pendingArgs: Parameters<F> | null;
    hasPending: boolean;
  };
  stateGuard.timerId = null;
  stateGuard.pendingArgs = null;
  stateGuard.hasPending = false;

  function clearPending(): void {
    if (stateGuard.timerId !== null) {
      clearTimeout(stateGuard.timerId);
      stateGuard.timerId = null;
    }
    stateGuard.pendingArgs = null;
    stateGuard.hasPending = false;
  }

  function invokeNow(): void {
    if (!stateGuard.hasPending || stateGuard.pendingArgs === null) {
      return;
    }
    const args = stateGuard.pendingArgs;
    clearPending();
    try {
      fn(...(args as Parameters<F>));
    } catch (err: unknown) {
      throw err;
    }
