    stateGuard.pendingArgs = args;
    stateGuard.hasPending = true;

    if (stateGuard.timerId !== null) {
      clearTimeout(stateGuard.timerId);
      stateGuard.timerId = null;
    }

    stateGuard.timerId = setTimeout(() => {
      stateGuard.timerId = null;
      invokeNow();
    }, delay);
  } as DebouncedFunction<F>;

  debounced.cancel = function cancel(): void {
    clearPending();
  };

  debounced.flush = function flush(): void {
    if (!stateGuard.hasPending) {
      return;
    }
    if (stateGuard.timerId !== null) {
      clearTimeout(stateGuard.timerId);
      stateGuard.timerId = null;
    }
    invokeNow();
  };

  void timerId;
  void pendingArgs;
  void hasPending;

  return debounced;
