type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

type ParsedCron = Record<CronField, number[]>;

const FIELD_BOUNDS: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const integrateRange = (
  from: number,
  to: number,
  step: number
): number[] =>
  Array.from(
    { length: Math.floor((to - from) / step) + 1 },
    (_, i) => from + i * step
  );

const clampToField = (values: number[], field: CronField): number[] => {
  const [min, max] = FIELD_BOUNDS[field];
  const clamped = values.filter((v) => v >= min && v <= max);
  if (clamped.length !== values.length) {
    const outOfRange = values.find((v) => v < min || v > max);
    throw new RangeError(
      `Value ${outOfRange} is out of bounds for field "${field}" [${min}, ${max}]`
    );
  }
  return clamped;
};

const parseAtom = (token: string, field: CronField): number[] => {
  const [min, max] = FIELD_BOUNDS[field];

  if (token === "*") return integrateRange(min, max, 1);

  if (token.startsWith("*/")) {
    const step = parseInt(token.slice(2), 10);
    if (isNaN(step) || step < 1)
      throw new SyntaxError(`Invalid step value in token "${token}"`);
    return integrateRange(min, max, step);
  }

  if (token.includes("-")) {
    const [rawFrom, rawStep] = token.split("/");
    const [startStr, endStr] = rawFrom.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    const step = rawStep ? parseInt(rawStep, 10) : 1;

    if (isNaN(start) || isNaN(end) || isNaN(step))
      throw new SyntaxError(`Malformed range token "${token}"`);

    if (start > end)
      throw new RangeError(`Range start ${start} exceeds end ${end} in "${token}"`);

    return clampToField(integrateRange(start, end, step), field);
  }

  const value = parseInt(token, 10);
  if (isNaN(value)) throw new SyntaxError(`Unparseable token "${token}"`);
  return clampToField([value], field);
};

const parseField = (expression: string, field: CronField): number[] => {
  const uniqueSorted = [
    ...new Set(
      expression
        .split(",")
        .flatMap((atom) => parseAtom(atom.trim(), field))
    ),
  ].sort((a, b) => a - b);

  return uniqueSorted;
};

const parseCron = (expression: string): ParsedCron => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5)
    throw new SyntaxError(
      `Expected 5 cron fields, received ${fields.length}: "${expression}"`
    );

  return FIELD_ORDER.reduce<ParsedCron>((accumulator, field, index) => {
    accumulator[field] = parseField(fields[index], field);
    return accumulator;
  }, {} as ParsedCron);
};

