  state.pendingArgs = null;

  const cancel = (): void => {
    if (state.timerId !== null) {
      clearTimeout(state.timerId);
      state.timerId = null;
    }
    state.pendingArgs = null;
  };

  const flush = (): void => {
    if (state.timerId === null || state.pendingArgs === null) {
      return;
    }
    clearTimeout(state.timerId);
    state.timerId = null;
    const args = state.pendingArgs;
    state.pendingArgs = null;
    fn(...args);
  };

  const debounced = (...args: Parameters<T>): void => {
    if (!Array.isArray(args)) {
      throw new TypeError(`Expected arguments to be array-like, got: ${typeof args}`);
    }

    state.pendingArgs = args;

    if (state.timerId !== null) {
      clearTimeout(state.timerId);
      state.timerId = null;
    }

    state.timerId = setTimeout(() => {
      state.timerId = null;
      const pendingArgs = state.pendingArgs;
      state.pendingArgs = null;

      if (pendingArgs === null) {
        return;
      }

      fn(...pendingArgs);
    }, delay);
  };

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

