// Recursive helper that carries the current key prefix down the tree.
// We separate this from the public API so callers never have to pass `prefix`.
function flatten(
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  input: Record<string, any>,
  prefix: string,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  result: Record<string, any>
): void {
  for (const key of Object.keys(input)) {
    // Build the dotted path — no leading dot when prefix is empty
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = input[key];

    const isPlainObject =
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp);

    if (isPlainObject && Object.keys(value).length > 0) {
      // Recurse deeper — only when there are actual child keys.
      // An empty object {} becomes a leaf so it isn't silently swallowed.
      flatten(value, fullKey, result);
    } else {
      // Leaf value: primitives, arrays, Date, RegExp, null, and empty objects
      result[fullKey] = value;
    }
  }
}

// Public surface. Accepts any plain object; returns a shallow, dot-keyed copy.
// We intentionally keep the signature broad (unknown values) so callers don't
// need to cast at the call site, but we validate the top-level shape before
// doing anything meaningful.
export default function flattenObject(
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  input: Record<string, any>
): Record<string, unknown> {
  // Guard against accidental null / non-object calls at runtime
  if (input === null || typeof input !== "object" || Array.isArray(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, got ${
        input === null ? "null" : Array.isArray(input) ? "array" : typeof input
      }`
    );
  }

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const result: Record<string, any> = {};
  flatten(input, "", result);
  return result;
}
