type AnyFunction = (...args: unknown[]) => unknown;

interface DebouncedFunction<T extends AnyFunction> {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
}

function debounce<T extends AnyFunction>(fn: T, delay: number): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(`Expected a function, got ${typeof fn}`);
  }
  if (typeof delay !== "number") {
    throw new TypeError(`Expected delay to be a number, got ${typeof delay}`);
  }
  if (!Number.isFinite(delay)) {
    throw new TypeError(`Expected delay to be a finite number, got ${delay}`);
  }
  if (delay < 0) {
    throw new TypeError(`Expected delay to be non-negative, got ${delay}`);
  }

  const state = Object.create(null) as {
    timerId: ReturnType<typeof setTimeout> | null;
    pendingArgs: Parameters<T> | null;
  };

  state.timerId = null;
  state.pendingArgs = null;

  const cancel = (): void => {
    if (state.timerId !== null) {
      clearTimeout(state.timerId);
      state.timerId = null;
    }
    state.pendingArgs = null;
  };

  const flush = (): void => {
    if (state.pendingArgs === null) {
      return;
    }
    const args = state.pendingArgs;
    cancel();
    fn(...args);
  };

  const debounced = (...args: Parameters<T>): void => {
    if (!Array.isArray(args)) {
      throw new TypeError(`Expected args to be an array, got ${typeof args}`);
    }

    state.pendingArgs = args;

    if (state.timerId !== null) {
      clearTimeout(state.timerId);
      state.timerId = null;
    }

    state.timerId = setTimeout(() => {
      state.timerId = null;
      const pendingArgs = state.pendingArgs;
      state.pendingArgs = null;
      if (pendingArgs !== null) {
        fn(...pendingArgs);
      }
    }, delay);
  };

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

export default debounce;
