const RANGES = { minute:[0,59], hour:[0,23], dayOfMonth:[1,31], month:[1,12], dayOfWeek:[0,6] } as const
type Field = keyof typeof RANGES

const all = (f: Field) => { const [lo,hi]=RANGES[f]; return Array.from({length:hi-lo+1},(_,i)=>i+lo) }
const clamp = (v: number[], f: Field) => { const [lo,hi]=RANGES[f]; return v.filter(x=>x>=lo&&x<=hi) }

const parseField = (s: string, f: Field): number[] => {
  if(s==='*') return all(f)
  if(s.includes(',')) return clamp([...new Set(s.split(',').flatMap(p=>parseField(p,f)))],f)
  if(s.startsWith('*/')) { const step=+s.slice(2); return all(f).filter(v=>v%step===0) }
  if(s.includes('/')) { const [r,step]=s.split('/'); const base=parseField(r,f); return base.filter((_,i)=>i%+step===0) }
  if(s.includes('-')) { const [a,b]=s.split('-').map(Number); return clamp(Array.from({length:b-a+1},(_,i)=>i+a),f) }
  return clamp([+s],f)
}

export default function parseCron(expr: string) {
  const [minute,hour,dayOfMonth,month,dayOfWeek]=expr.trim().split(/\s+/)
  const fields:Field[]=['minute','hour','dayOfMonth','month','dayOfWeek']
  const vals=[minute,hour,dayOfMonth,month,dayOfWeek]
  if(vals.some(v=>v==null)) throw new Error('invalid')
  return Object.fromEntries(fields.map((f,i)=>[f,parseField(vals[i],f)])) as Record<Field,number[]>
} // @stance: minimal

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: string;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = Object.freeze([
  Object.freeze({ name: "minute", min: 0, max: 59 }),
  Object.freeze({ name: "hour", min: 0, max: 23 }),
  Object.freeze({ name: "dayOfMonth", min: 1, max: 31 }),
  Object.freeze({ name: "month", min: 1, max: 12 }),
  Object.freeze({ name: "dayOfWeek", min: 0, max: 6 }),
]);

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function assertSafeInteger(value: number, label: string): void {
  if (!Number.isInteger(value)) {
    throw new TypeError(`${label} must be an integer, got ${value}`);
  }
  if (!Number.isFinite(value)) {
    throw new TypeError(`${label} must be finite, got ${value}`);
  }
}

function parseStrictInt(raw: string, label: string): number {
  if (typeof raw !== "string") {
    throw new TypeError(`${label}: expected string token, got ${typeof raw}`);
  }
  if (raw.length === 0) {
    throw new TypeError(`${label}: token is empty`);
  }
  // Reject leading zeros (ambiguous, potential octal-intent confusion)
  if (raw.length > 1 && raw[0] === "0") {
    throw new TypeError(`${label}: leading zeros are not permitted in '${raw}'`);
  }
  // Reject anything that parseInt would silently truncate (e.g. "5.3", "5x")
  const n = parseInt(raw, 10);
  if (isNaN(n)) {
    throw new TypeError(`${label}: '${raw}' is not a valid integer`);
  }
  if (String(n) !== raw) {
    throw new TypeError(`${label}: '${raw}' is not a strict integer (got coercion to ${n})`);
  }
  return n;
}

function generateRange(min: number, max: number, label: string): number[] {
  assertSafeInteger(min, `${label}.rangeMin`);
  assertSafeInteger(max, `${label}.rangeMax`);
  if (min > max) {
    throw new RangeError(`${label}: range start ${min} must be <= range end ${max}`);
  }
  // Guard against absurd allocation — bounded by valid field ranges, but be explicit
  const count = max - min + 1;
  if (count > 10_000) {
    throw new RangeError(`${label}: range would generate ${count} values, which is unreasonably large`);
  }
  const result: number[] = [];
  for (let i = min; i <= max; i++) {
    result.push(i);
  }
  return result;
}

function assertInBounds(value: number, config: FieldConfig): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Field '${config.name}': value ${value} is out of bounds [${config.min}, ${config.max}]`
    );
  }
}

function parseFieldToken(token: string, config: FieldConfig): number[] {
  if (typeof token !== "string") {
    throw new TypeError(`Field '${config.name}': token must be a string, got ${typeof token}`);
  }
  if (token.length === 0) {
    throw new TypeError(`Field '${config.name}': token is empty`);
  }

  const { name, min, max } = config;

  // --- Step expression: base/step or */step or number/step ---
  if (token.includes("/")) {
    const slashCount = (token.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new TypeError(`Field '${name}': multiple '/' characters in '${token}'`);
    }
    const slashIdx = token.indexOf("/");
    if (slashIdx === 0) {
      throw new TypeError(`Field '${name}': step expression '${token}' has no base`);
    }
    if (slashIdx === token.length - 1) {
      throw new TypeError(`Field '${name}': step expression '${token}' has no step value`);
    }

    const baseExpr = token.slice(0, slashIdx);
    const stepRaw = token.slice(slashIdx + 1);

    const step = parseStrictInt(stepRaw, `Field '${name}' step`);
    if (step <= 0) {
      throw new RangeError(`Field '${name}': step must be a positive integer, got ${step}`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (baseExpr === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (baseExpr.includes("-")) {
      const [startRaw, endRaw, ...extra] = baseExpr.split("-");
      if (extra.length > 0) {
        throw new TypeError(`Field '${name}': multiple '-' in range base '${baseExpr}'`);
      }
      if (startRaw === undefined || endRaw === undefined) {
        throw new TypeError(`Field '${name}': malformed range base '${baseExpr}'`);
      }
      rangeMin = parseStrictInt(startRaw, `Field '${name}' range-start`);
      rangeMax = parseStrictInt(endRaw, `Field '${name}' range-end`);
    } else {
      rangeMin = parseStrictInt(baseExpr, `Field '${name}' step-base`);
      rangeMax = max;
    }

    assertInBounds(rangeMin, config);
    assertInBounds(rangeMax, config);
    if (rangeMin > rangeMax) {
      throw new RangeError(
        `Field '${name}': range start ${rangeMin} must be <= range end ${rangeMax}`
      );
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    if (values.length === 0) {
      throw new RangeError(`Field '${name}': step expression '${token}' produced no values`);
    }
    return values;
  }

  // --- Wildcard ---
  if (token === "*") {
    return generateRange(min, max, `Field '${name}'`);
  }

  // --- Range: start-end ---
  if (token.includes("-")) {
    const dashParts = token.split("-");
    if (dashParts.length !== 2) {
      throw new TypeError(
        `Field '${name}': range '${token}' must have exactly one '-' separator`
      );
    }
    const [startRaw, endRaw] = dashParts;
    if (!startRaw || !endRaw) {
      throw new TypeError(`Field '${name}': range '${token}' has an empty start or end`);
    }
    const start = parseStrictInt(startRaw, `Field '${name}' range-start`);
    const end = parseStrictInt(endRaw, `Field '${name}' range-end`);
    assertInBounds(start, config);
    assertInBounds(end, config);
    if (start > end) {
      throw new RangeError(
        `Field '${name}': range start ${start} must be <= range end ${end}`
      );
    }
    return generateRange(start, end, `Field '${name}'`);
  }

  // --- Single numeric value ---
  const value = parseStrictInt(token, `Field '${name}'`);
  assertInBounds(value, config);
  return [value];
}

function parseField(expression: string, config: FieldConfig): number[] {
  if (typeof expression !== "string") {
    throw new TypeError(
      `Field '${config.name}': expression must be a string, got ${typeof expression}`
    );
  }
  if (expression.length === 0) {
    throw new TypeError(`Field '${config.name}': expression is empty`);
  }

  // --- Comma-separated list ---
  if (expression.includes(",")) {
    const parts = expression.split(",");
    if (parts.length < 2) {
      throw new TypeError(
        `Field '${config.name}': comma present but fewer than 2 segments in '${expression}'`
      );
    }

    const seen = new Set<number>();
    const values: number[] = [];

    for (let i = 0; i < parts.length; i++) {
      const part = parts[i];
      if (part === undefined || part === null) {
        throw new TypeError(`Field '${config.name}': segment at index ${i} is nullish`);
      }
      const trimmed = part.trim();
      if (trimmed.length === 0) {
        throw new TypeError(
          `Field '${config.name}': empty segment at index ${i} in list '${expression}'`
        );
      }
      if (trimmed.includes(",")) {
        // Should be impossible after split, but we are paranoid
        throw new TypeError(
          `Field '${config.name}': nested comma found in segment '${trimmed}' — parser invariant violated`
        );
      }

      const subValues = parseFieldToken(trimmed, config);
      for (const v of subValues) {
        if (!seen.has(v)) {
          seen.add(v);
          values.push(v);
        }
      }
    }

    if (values.length === 0) {
      throw new RangeError(
        `Field '${config.name}': list expression '${expression}' produced no values`
      );
    }

    return values.sort((a, b) => a - b);
  }

  // --- Single token (wildcard, step, range, or number) ---
  return parseFieldToken(expression, config);
}

export default function parseCron(expression: unknown): CronFields {
  // Aggressively validate the top-level input — trust nothing
  if (expression === null) {
    throw new TypeError("parseCron: expression must be a string, got null");
  }
  if (expression === undefined) {
    throw new TypeError("parseCron: expression must be a string, got undefined");
  }
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron: expression must be a string, got ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new TypeError(
      "parseCron: expression must not be empty or whitespace-only"
    );
  }

  // Reject null bytes and other control characters that could corrupt parsing
  // eslint-disable-next-line no-control-regex
  if (/[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]/.test(trimmed)) {
    throw new TypeError(
      "parseCron: expression contains illegal control characters"
    );
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new TypeError(
      `parseCron: expected exactly 5 whitespace-separated fields, got ${fields.length} in '${trimmed}'`
    );
  }

  // Use Object.create(null) to avoid any prototype-chain surprises on the raw map
  const rawFields = Object.create(null) as { [K in typeof FIELD_NAMES[number]]: string };

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const fieldName = FIELD_NAMES[i];
    const fieldValue = fields[i];
    if (fieldName === undefined) {
      throw new TypeError(`parseCron: internal error — field name at index ${i} is undefined`);
    }
    if (fieldValue === undefined || fieldValue === null || fieldValue.length === 0) {
      throw new TypeError(`parseCron: internal error — field value at index ${i} is empty`);
    }
    rawFields[fieldName] = fieldValue;
  }

  const result: CronFields = {
    minute: parseField(rawFields["minute"], FIELD_CONFIGS[0]!),
    hour: parseField(rawFields["hour"], FIELD_CONFIGS[1]!),
    dayOfMonth: parseField(rawFields["dayOfMonth"], FIELD_CONFIGS[2]!),
    month: parseField(rawFields["month"], FIELD_CONFIGS[3]!),
    dayOfWeek: parseField(rawFields["dayOfWeek"], FIELD_CONFIGS[4]!),
  };

  // Final sanity sweep — internal logic should never produce empty arrays, but verify anyway
  for (const fieldName of FIELD_NAMES) {
    const arr = result[fieldName];
    if (!Array.isArray(arr)) {
      throw new TypeError(
        `parseCron: internal error — '${fieldName}' did not resolve to an array`
      );
    }
    if (arr.length === 0) {
      throw new RangeError(
        `parseCron: internal error — '${fieldName}' resolved to an empty array`
      );
    }
    for (let i = 0; i < arr.length; i++) {
      const v = arr[i];
      if (v === undefined || !Number.isInteger(v)) {
        throw new TypeError(
          `parseCron: internal error — '${fieldName}[${i}]' is not a safe integer: ${v}`
        );
      }
    }
  }

  return result;
}
