interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function parseField(field: string, config: FieldConfig): number[] {
  const { min, max } = config;

  const allValues = (): number[] =>
    Array.from({ length: max - min + 1 }, (_, i) => i + min);

  const clampedRange = (start: number, end: number): number[] => {
    if (start < min || end > max || start > end) {
      throw new RangeError(
        `Range ${start}-${end} is out of bounds [${min}, ${max}]`
      );
    }
    return Array.from({ length: end - start + 1 }, (_, i) => i + start);
  };

  const parseNumber = (s: string): number => {
    const n = parseInt(s, 10);
    if (isNaN(n)) throw new TypeError(`Invalid value: "${s}"`);
    if (n < min || n > max)
      throw new RangeError(`Value ${n} out of bounds [${min}, ${max}]`);
    return n;
  };

  const parseSingle = (token: string): number[] => {
    if (token === "*") return allValues();

    if (token.startsWith("*/")) {
      const step = parseInt(token.slice(2), 10);
      if (isNaN(step) || step <= 0)
        throw new TypeError(`Invalid step value in: "${token}"`);
      const result: number[] = [];
      for (let v = min; v <= max; v += step) result.push(v);
      return result;
    }

    if (token.includes("-")) {
      const parts = token.split("-");
      if (parts.length !== 2)
        throw new SyntaxError(`Invalid range: "${token}"`);
      const [start, end] = parts.map((p) => {
        const n = parseInt(p, 10);
        if (isNaN(n)) throw new TypeError(`Invalid range bound: "${p}"`);
        return n;
      });

      if (token.includes("/")) {
        throw new SyntaxError(`Use "start-end/step" via range-step syntax: "${token}"`);
      }

      return clampedRange(start, end);
    }

    if (token.includes("/")) {
      const [rangePart, stepPart] = token.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0)
        throw new TypeError(`Invalid step value in: "${token}"`);

      let rangeValues: number[];
      if (rangePart === "*") {
        rangeValues = allValues();
      } else if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map((p) => parseInt(p, 10));
        rangeValues = clampedRange(s, e);
      } else {
        const start = parseInt(rangePart, 10);
        rangeValues = clampedRange(start, max);
      }

      return rangeValues.filter((v) => (v - rangeValues[0]) % step === 0);
    }

    return [parseNumber(token)];
  };

  if (field.includes(",")) {
    const tokens = field.split(",");
    const values = new Set<number>();
    for (const token of tokens) {
      for (const v of parseSingle(token.trim())) values.add(v);
    }
    return [...values].sort((a, b) => a - b);
  }

  return parseSingle(field);
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const keys = Object.keys(FIELD_CONFIGS) as (keyof CronResult)[];
  const rawFields = [minuteField, hourField, domField, monthField, dowField];

  const result = {} as CronResult;
  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    try {
      result[key] = parseField(rawFields[i], FIELD_CONFIGS[key]);
    } catch (err) {
      throw new Error(
        `Invalid cron field "${key}" with value "${rawFields[i]}": ${(err as Error).message}`
      );
    }
  }

  return result;
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: Primitive };

function isPrimitive(value: unknown): value is Primitive {
  if (value === null || value === undefined) return true;
  const t = typeof value;
  return t === "string" || t === "number" || t === "boolean" || t === "bigint" || t === "symbol";
}

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || value === undefined) return false;
  if (typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map) return false;
  if (value instanceof Set) return false;
  if (value instanceof WeakMap) return false;
  if (value instanceof WeakSet) return false;
  if (value instanceof Promise) return false;
  if (value instanceof Error) return false;
  if (value instanceof ArrayBuffer) return false;
  if (ArrayBuffer.isView(value)) return false;
  return true;
}

function flattenObject(
  input: unknown,
  maxDepth: number = 64
): FlatObject {
  if (input === null || input === undefined) {
    throw new TypeError(
      `flattenObject: input must be a plain object, received ${input === null ? "null" : "undefined"}`
    );
  }

  if (typeof input !== "object") {
    throw new TypeError(
      `flattenObject: input must be a plain object, received ${typeof input}`
    );
  }

  if (Array.isArray(input)) {
    throw new TypeError(
      "flattenObject: input must be a plain object, received Array"
    );
  }

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject: input must be a plain object, received ${Object.prototype.toString.call(input)}`
    );
  }

  if (typeof maxDepth !== "number" || !Number.isFinite(maxDepth) || maxDepth < 1) {
    throw new TypeError(
      `flattenObject: maxDepth must be a positive finite number, received ${maxDepth}`
    );
  }

  if (maxDepth > 1024) {
    throw new TypeError(
      `flattenObject: maxDepth must not exceed 1024 to prevent stack overflow, received ${maxDepth}`
    );
  }

