        "flattenObject: empty-string keys are not permitted — they produce ambiguous dot-notation paths"
      );
    }

    if (key.includes("\0")) {
      throw new TypeError(
        `flattenObject: key "${key}" contains a null byte, which is not permitted`
      );
    }

    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value: unknown = safeInput[key];

    if (isPlainObject(value)) {
      const nested = flattenObject(value, fullKey, depth + 1);
      const nestedKeys = Object.keys(nested);

      for (let j = 0; j < nestedKeys.length; j++) {
        const nestedKey = nestedKeys[j];
        result[nestedKey] = nested[nestedKey];
      }
    } else if (
      typeof value === "string" ||
      typeof value === "number" ||
      typeof value === "boolean" ||
      typeof value === "bigint" ||
      typeof value === "symbol" ||
      value === null ||
      value === undefined
    ) {
      result[fullKey] = value as Primitive;
    } else if (Array.isArray(value)) {
      // Arrays are not recursed — stored as-is would violate the Primitive type.
      // Throw to surface the ambiguity rather than silently mangle data.
      throw new TypeError(
        `flattenObject: value at key "${fullKey}" is an Array; arrays are not supported — flatten arrays before passing`
      );
    } else {
      // Non-plain objects (Date, Map, Error, etc.) at leaf positions
      throw new TypeError(
        `flattenObject: value at key "${fullKey}" is a non-serialisable object (${Object.prototype.toString.call(value)}); only plain objects and primitives are supported`
      );
    }
  }

  return result;
}

export default flattenObject;
