type Debounced<T extends (...args: any[]) => any> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: any[]) => any>(fn: T, delay: number): Debounced<T> {
  let t: ReturnType<typeof setTimeout> | null = null;
  let pending: Parameters<T> | null = null;

  const d = (...args: Parameters<T>) => {
    pending = args;
    if (t) clearTimeout(t);
    t = setTimeout(() => { fn(...pending!); t = null; pending = null; }, delay);
  };

  d.cancel = () => { if (t) { clearTimeout(t); t = null; pending = null; } };
  d.flush = () => { if (t) { clearTimeout(t); t = null; fn(...pending!); pending = null; } };

  return d;
} // @stance: minimal

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

type ParsedCron = Record<CronField, number[]>;

const cronFieldBounds: Record<CronField, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   7],
};

const cronFieldOrder: CronField[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

const rangeOfBounds = ([min, max]: [number, number]): number[] =>
  Array.from({ length: max - min + 1 }, (_, i) => i + min);

const clampToBounds = (value: number, [min, max]: [number, number]): number => {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of bounds [${min}, ${max}]`);
  }
  return value;
};

const expandStepExpression = (
  token: string,
  bounds: [number, number]
): number[] => {
  const [baseToken, stepStr] = token.split("/");
  const step = parseInt(stepStr, 10);

  if (isNaN(step) || step <= 0) {
    throw new SyntaxError(`Invalid step value: "${stepStr}"`);
  }

  const baseValues =
    baseToken === "*"
      ? rangeOfBounds(bounds)
      : expandSingleToken(baseToken, bounds);

  return baseValues.filter((v) => (v - baseValues[0]) % step === 0);
};

const expandRangeExpression = (
  token: string,
  bounds: [number, number]
): number[] => {
  const [startStr, endStr] = token.split("-");
  const start = clampToBounds(parseInt(startStr, 10), bounds);
  const end   = clampToBounds(parseInt(endStr,   10), bounds);

  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end}`);
  }

  return Array.from({ length: end - start + 1 }, (_, i) => i + start);
};

const expandSingleToken = (
  token: string,
  bounds: [number, number]
): number[] => {
  if (token === "*")        return rangeOfBounds(bounds);
  if (token.includes("/"))  return expandStepExpression(token, bounds);
  if (token.includes("-"))  return expandRangeExpression(token, bounds);

  const value = parseInt(token, 10);

  if (isNaN(value)) {
    throw new SyntaxError(`Unrecognized cron token: "${token}"`);
  }

  return [clampToBounds(value, bounds)];
};

const expandFieldExpression = (
  expression: string,
  bounds: [number, number]
): number[] => {
  const deduplicatedSortedValues = [
    ...new Set(
      expression
        .split(",")
        .flatMap((token) => expandSingleToken(token.trim(), bounds))
    ),
  ].sort((a, b) => a - b);

  return deduplicatedSortedValues;
};

const parseCron = (cronExpression: string): ParsedCron => {
  const fields = cronExpression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${fields.length}: "${cronExpression}"`
    );
  }

  return Object.fromEntries(
    cronFieldOrder.map((fieldName, index) => [
      fieldName,
      expandFieldExpression(fields[index], cronFieldBounds[fieldName]),
    ])
  ) as ParsedCron;
};

export default parseCron;
