type AnyFunction = (...args: unknown[]) => unknown;

interface DebouncedFunction<T extends AnyFunction> {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
}

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(
      `debounce: expected first argument to be a function, got ${typeof fn}`
    );
  }

  if (typeof delay !== "number") {
    throw new TypeError(
      `debounce: expected second argument to be a number, got ${typeof delay}`
    );
  }

  if (!Number.isFinite(delay)) {
    throw new TypeError(
      `debounce: delay must be a finite number, got ${delay}`
    );
  }

  if (delay < 0) {
    throw new TypeError(
      `debounce: delay must be non-negative, got ${delay}`
    );
  }

  const state = Object.create(null) as {
    timerId: ReturnType<typeof setTimeout> | null;
    pendingArgs: Parameters<T> | null;
  };

  state.timerId = null;
  state.pendingArgs = null;

  const clearPending = (): void => {
    if (state.timerId !== null) {
      clearTimeout(state.timerId);
      state.timerId = null;
    }
  };

  const invokePending = (): void => {
    const args = state.pendingArgs;
    clearPending();
    state.pendingArgs = null;
    if (args !== null) {
      fn(...args);
    }
  };

  const debounced = function (...args: Parameters<T>): void {
    if (args === undefined || args === null) {
      throw new TypeError(
        "debounce: internal error — args must be a valid arguments list"
      );
    }
    state.pendingArgs = args;
    clearPending();
    state.timerId = setTimeout(() => {
      invokePending();
    }, delay);
  } as DebouncedFunction<T>;

  debounced.cancel = (): void => {
    clearPending();
    state.pendingArgs = null;
  };

  debounced.flush = (): void => {
    invokePending();
  };

  return debounced;
}
// @stance: paranoid

type AnyFunction = (...args: Parameters<AnyFunction>) => ReturnType<AnyFunction>;

type DebouncedFunction<F extends AnyFunction> = {
  (...args: Parameters<F>): ReturnType<F> | undefined;
  cancel: () => void;
  flush: () => ReturnType<F> | undefined;
};

const debounce = <F extends AnyFunction>(
  fn: F,
  delayMs: number
): DebouncedFunction<F> => {
  let pendingTimerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<F> | undefined;

  const invokeWithPendingArgs = (): ReturnType<F> | undefined =>
    pendingArgs !== undefined ? fn(...pendingArgs) : undefined;

  const clearPendingTimer = (): void => {
    if (pendingTimerId !== undefined) {
      clearTimeout(pendingTimerId);
      pendingTimerId = undefined;
    }
  };

  const scheduleInvocation = (args: Parameters<F>): void => {
    clearPendingTimer();
    pendingArgs = args;
    pendingTimerId = setTimeout(() => {
      pendingTimerId = undefined;
      pendingArgs = undefined;
      fn(...args);
    }, delayMs);
  };

  const debouncedFn = (...args: Parameters<F>): ReturnType<F> | undefined => {
    scheduleInvocation(args);
    return undefined;
  };

  debouncedFn.cancel = (): void => {
    clearPendingTimer();
    pendingArgs = undefined;
  };

  debouncedFn.flush = (): ReturnType<F> | undefined => {
    clearPendingTimer();
    const result = invokeWithPendingArgs();
    pendingArgs = undefined;
    return result;
  };

  return debouncedFn;
};

export default debounce;
