const isObj = (v: unknown): v is Record<string, unknown> =>
  !!v && typeof v === "object" && !Array.isArray(v);

const deepMerge = (t: Record<string, unknown>, s: Record<string, unknown>): Record<string, unknown> =>
  Object.keys({ ...t, ...s }).reduce((acc, k) => {
    acc[k] = isObj(t[k]) && isObj(s[k])
      ? deepMerge(t[k], s[k])
      : Array.isArray(t[k]) && Array.isArray(s[k])
      ? [...(t[k] as unknown[]), ...(s[k] as unknown[])]
      : k in s ? s[k] : t[k];
    return acc;
  }, {} as Record<string, unknown>);

export default deepMerge;
