type Primitive = string | number | boolean | null | undefined;

type FlattenedObject = Record<string, Primitive>;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<Primitive | NestedObject>;
};

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        if (item !== null && typeof item === "object") {
          flattenObject(item as NestedObject, key, result);
        } else {
          result[key] = item as Primitive;
        }
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object") {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatRecord = Record<string, Primitive>;

const isPrimitiveLike = (value: unknown): value is Primitive =>
  value === null ||
  value === undefined ||
  typeof value === "string" ||
  typeof value === "number" ||
  typeof value === "boolean";

const isPlainObject = (value: unknown): value is NestedObject =>
  typeof value === "object" &&
  value !== null &&
  !Array.isArray(value) &&
  !(value instanceof Date) &&
  !(value instanceof RegExp);

const flattenWithPrefix = (
  node: unknown,
  prefix: string,
  accumulator: FlatRecord
): FlatRecord => {
  if (isPrimitiveLike(node) || !isPlainObject(node)) {
    accumulator[prefix] = node as Primitive;
    return accumulator;
  }

  const childKeys = Object.keys(node);

  if (childKeys.length === 0) {
    accumulator[prefix] = {} as unknown as Primitive;
    return accumulator;
  }

  return childKeys.reduce((acc, key) => {
    const deeperPrefix = prefix ? `${prefix}.${key}` : key;
    return flattenWithPrefix(node[key], deeperPrefix, acc);
  }, accumulator);
};

const flattenObject = (input: NestedObject): FlatRecord =>
  Object.keys(input).reduce(
    (acc, key) => flattenWithPrefix(input[key], key, acc),
    {} as FlatRecord
  );

export default flattenObject;
// @stance: creative

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    typeof value === "object" &&
    value !== null &&
    !Array.isArray(value) &&
    Object.getPrototypeOf(value) === Object.prototype
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;

  const debounced = function (...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      const args = pendingArgs!;
      pendingArgs = undefined;
      fn(...args);
    }, delay);
  } as DebouncedFunction<T>;

  debounced.cancel = function (): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
  };

  debounced.flush = function (): void {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
      const args = pendingArgs!;
      pendingArgs = undefined;
      fn(...args);
    }
  };

  return debounced;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

interface FieldMeta {
  readonly name: FieldName;
  readonly min: number;
  readonly max: number;
}

const FIELD_DEFS: readonly FieldMeta[] = Object.freeze([
  Object.freeze({ name: "minute" as const,     min: 0,  max: 59 }),
  Object.freeze({ name: "hour" as const,        min: 0,  max: 23 }),
  Object.freeze({ name: "dayOfMonth" as const,  min: 1,  max: 31 }),
  Object.freeze({ name: "month" as const,       min: 1,  max: 12 }),
  Object.freeze({ name: "dayOfWeek" as const,   min: 0,  max: 6  }),
]);

const FIELD_COUNT = 5 as const;

function strictParseInt(raw: string, context: string): number {
  if (typeof raw !== "string") {
    throw new TypeError(`[${context}] expected string token, got ${typeof raw}`);
  }
  const trimmed = raw.trim();
  if (trimmed.length === 0) {
    throw new TypeError(`[${context}] integer token is empty`);
  }
  if (!/^\d+$/.test(trimmed)) {
    throw new TypeError(`[${context}] '${trimmed}' is not a valid non-negative integer`);
  }
  const n = Number(trimmed);
  if (!Number.isFinite(n) || !Number.isInteger(n)) {
    throw new TypeError(`[${context}] '${trimmed}' did not produce a finite integer`);
  }
  return n;
}

function assertInRange(value: number, meta: FieldMeta, context: string): void {
  if (value < meta.min || value > meta.max) {
    throw new RangeError(
      `[${context}] value ${value} is out of valid range [${meta.min}, ${meta.max}] for field '${meta.name}'`
    );
  }
}

function buildRange(from: number, to: number, step: number, meta: FieldMeta, context: string): number[] {
  if (!Number.isInteger(step) || step < 1) {
    throw new RangeError(`[${context}] step must be a positive integer >= 1, got: ${step}`);
  }
  if (from > to) {
    throw new RangeError(`[${context}] range start ${from} exceeds range end ${to} for field '${meta.name}'`);
  }
  assertInRange(from, meta, context);
  assertInRange(to, meta, context);

  const result: number[] = [];
  for (let i = from; i <= to; i += step) {
    result.push(i);
  }
  if (result.length === 0) {
    throw new RangeError(`[${context}] range produced zero values for field '${meta.name}'`);
  }
  return result;
}

function parseSegment(raw: string, meta: FieldMeta, context: string): number[] {
  if (typeof raw !== "string") {
    throw new TypeError(`[${context}] segment must be a string, got: ${typeof raw}`);
  }
  const token = raw.trim();
  if (token.length === 0) {
    throw new TypeError(`[${context}] segment for field '${meta.name}' is empty`);
  }

  // Step: */N  or  A-B/N  or  N/N
  if (token.indexOf("/") !== -1) {
    const slashIdx = token.indexOf("/");
    if (slashIdx === 0) {
      throw new TypeError(`[${context}] '${token}' has nothing before '/'; expected '*', range, or number`);
    }
    if (slashIdx === token.length - 1) {
      throw new TypeError(`[${context}] '${token}' has nothing after '/'; step value is required`);
    }
    const lhs = token.slice(0, slashIdx);
    const rhsStr = token.slice(slashIdx + 1);
    const step = strictParseInt(rhsStr, `${context}/step`);
    if (step < 1) {
      throw new RangeError(`[${context}] step must be >= 1, got: ${step}`);
    }

    if (lhs === "*") {
      return buildRange(meta.min, meta.max, step, meta, context);
    }
    if (lhs.indexOf("-") !== -1) {
      const dashIdx = lhs.indexOf("-");
      if (dashIdx === 0 || dashIdx === lhs.length - 1) {
        throw new TypeError(`[${context}] malformed range in step expression: '${token}'`);
      }
      const from = strictParseInt(lhs.slice(0, dashIdx), `${context}/range-start`);
      const to   = strictParseInt(lhs.slice(dashIdx + 1), `${context}/range-end`);
      return buildRange(from, to, step, meta, context);
    }
    // N/step → start at N, step to max
    const start = strictParseInt(lhs, `${context}/step-start`);
    assertInRange(start, meta, context);
    return buildRange(start, meta.max, step, meta, context);
  }

  // Wildcard
  if (token === "*") {
    return buildRange(meta.min, meta.max, 1, meta, context);
  }

  // Range: A-B
  if (token.indexOf("-") !== -1) {
    const dashIdx = token.indexOf("-");
    if (dashIdx === 0 || dashIdx === token.length - 1) {
      throw new TypeError(`[${context}] malformed range expression: '${token}'`);
    }
    const from = strictParseInt(token.slice(0, dashIdx), `${context}/range-start`);
    const to   = strictParseInt(token.slice(dashIdx + 1), `${context}/range-end`);
    return buildRange(from, to, 1, meta, context);
  }

  // Plain integer
  const num = strictParseInt(token, `${context}/number`);
  assertInRange(num, meta, context);
  return [num];
}

function parseField(raw: string, meta: FieldMeta): number[] {
  if (typeof raw !== "string") {
    throw new TypeError(`parseField: expected string for '${meta.name}', got: ${typeof raw}`);
  }
  if (raw.trim().length === 0) {
    throw new TypeError(`parseField: field '${meta.name}' value is empty`);
  }

  const context = `field:${meta.name}`;

  // Comma-separated list — must be checked before anything else
  if (raw.indexOf(",") !== -1) {
    const parts = raw.split(",");
    if (parts.length < 2) {
      throw new TypeError(`[${context}] comma-list must contain at least two entries`);
    }
    const seen = new Set<number>();
    for (let i = 0; i < parts.length; i++) {
      const part = parts[i];
      if (typeof part !== "string" || part.trim().length === 0) {
        throw new TypeError(`[${context}] empty entry at index ${i} in comma-separated list`);
      }
      // Disallow nested commas (already split, so this is defensive)
      if (part.indexOf(",") !== -1) {
        throw new TypeError(`[${context}] unexpected nested comma in part '${part}'`);
      }
      const vals = parseSegment(part.trim(), meta, `${context}[${i}]`);
      for (const v of vals) {
        seen.add(v);
      }
    }
    if (seen.size === 0) {
      throw new RangeError(`[${context}] comma-list produced zero values`);
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSegment(raw.trim(), meta, context);
}

export default function parseCron(expression: string): CronFields {
  if (expression === null || expression === undefined) {
    throw new TypeError(
      `parseCron: expression must be a non-null, non-undefined string; received: ${String(expression)}`
    );
  }
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron: expression must be a string, got: ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new TypeError("parseCron: expression must not be blank or whitespace-only");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== FIELD_COUNT) {
    throw new TypeError(
      `parseCron: expected exactly ${FIELD_COUNT} whitespace-separated fields, got ${fields.length} in: '${trimmed}'`
    );
  }

  // Object.create(null) — no prototype, no __proto__ pollution risk
  const result = Object.create(null) as CronFields;

  for (let i = 0; i < FIELD_DEFS.length; i++) {
    const meta = FIELD_DEFS[i];
    if (meta === undefined || meta === null) {
      throw new TypeError(`parseCron: FIELD_DEFS[${i}] is unexpectedly ${meta}`);
    }
    const rawField = fields[i];
    if (rawField === undefined || rawField === null) {
      throw new TypeError(`parseCron: fields[${i}] is unexpectedly ${rawField}`);
    }
    const parsed = parseField(rawField, meta);
    if (!Array.isArray(parsed) || parsed.length === 0) {
      throw new RangeError(
        `parseCron: parsing field '${meta.name}' ('${rawField}') produced an empty result`
      );
    }
    result[meta.name] = parsed;
  }

  // Final integrity check — all five keys must be present and non-empty arrays
  for (const meta of FIELD_DEFS) {
    const arr = result[meta.name];
    if (!Array.isArray(arr) || arr.length === 0) {
      throw new RangeError(`parseCron: post-parse integrity failure on field '${meta.name}'`);
    }
    for (const v of arr) {
      if (typeof v !== "number" || !Number.isInteger(v) || v < meta.min || v > meta.max) {
        throw new RangeError(
          `parseCron: post-parse value ${v} in field '${meta.name}' failed integrity check [${meta.min}, ${meta.max}]`
        );
      }
    }
  }

  return result;
}
