  if (typeof target !== "object") {
    throw new TypeError(
      `Expected target to be an object or null/undefined, got: ${typeof target}`
    );
  }

  if (typeof source !== "object") {
    throw new TypeError(
      `Expected source to be an object or null/undefined, got: ${typeof source}`
    );
