  if (Array.isArray(target) && Array.isArray(source)) {
    const targetArr = target as unknown[];
    const sourceArr = source as unknown[];

    if (!Array.isArray(targetArr) || !Array.isArray(sourceArr)) {
      throw new TypeError("Array check failed unexpectedly — aborting merge");
    }

    return [...targetArr, ...sourceArr];
  }

  // Array/object mismatch — source wins
  if (Array.isArray(target) !== Array.isArray(source)) {
    return source;
  }

  // Both plain objects — merge recursively
  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = Object.create(null);

    // Copy all target keys first
    for (const key of Object.keys(target)) {
      if (Object.prototype.hasOwnProperty.call(target, key)) {
        result[key] = target[key];
      }
    }

    // Merge/overwrite with source keys
    for (const key of Object.keys(source)) {
      if (!Object.prototype.hasOwnProperty.call(source, key)) continue;

      const sourceVal = source[key];
      const targetVal = result[key];

      const bothObjects = isPlainObject(targetVal) && isPlainObject(sourceVal);
      const bothArrays = Array.isArray(targetVal) && Array.isArray(sourceVal);

      if (bothObjects || bothArrays) {
        result[key] = deepMerge(targetVal, sourceVal);
      } else {
        result[key] = sourceVal;
      }
    }

    return result;
  }

  // Fallback: source overwrites target
  return source;
}

