interface DebouncedFunction<T extends AnyFunction> {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
}

function debounce<T extends AnyFunction>(fn: T, delay: number): DebouncedFunction<T> {
  if (fn === null || fn === undefined) {
    throw new TypeError(`debounce: 'fn' must be a function, got ${fn}`);
  }
  if (typeof fn !== "function") {
    throw new TypeError(`debounce: 'fn' must be a function, got ${typeof fn}`);
  }
  if (delay === null || delay === undefined) {
    throw new TypeError(`debounce: 'delay' must be a number, got ${delay}`);
  }
  if (typeof delay !== "number") {
    throw new TypeError(`debounce: 'delay' must be a number, got ${typeof delay}`);
  }
  if (!isFinite(delay)) {
    throw new TypeError(`debounce: 'delay' must be a finite number, got ${delay}`);
  }
  if (delay < 0) {
    throw new TypeError(`debounce: 'delay' must be non-negative, got ${delay}`);
  }

  const state = Object.create(null) as {
    timerId: ReturnType<typeof setTimeout> | null;
    pendingArgs: Parameters<T> | null;
    hasPending: boolean;
  };

  state.timerId = null;
  state.pendingArgs = null;
  state.hasPending = false;

  const clearPending = (): void => {
    if (state.timerId !== null) {
      clearTimeout(state.timerId);
      state.timerId = null;
    }
    state.pendingArgs = null;
    state.hasPending = false;
  };

  const invokePending = (): void => {
    if (!state.hasPending) {
      return;
    }
    const args = state.pendingArgs;
    clearPending();
    if (args === null) {
      throw new TypeError("debounce: internal invariant violated — hasPending was true but pendingArgs was null");
    }
    fn(...args);
  };

  const debounced = (...args: Parameters<T>): void => {
    if (args === null || args === undefined) {
      throw new TypeError("debounce: internal error — args is nullish");
    }

    state.pendingArgs = args;
    state.hasPending = true;

    if (state.timerId !== null) {
      clearTimeout(state.timerId);
      state.timerId = null;
    }

    state.timerId = setTimeout(() => {
      state.timerId = null;
      invokePending();
    }, delay);
  };

  debounced.cancel = (): void => {
    clearPending();
  };

  debounced.flush = (): void => {
    invokePending();
  };

  return debounced;
}

