    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  debounced.flush = function (): void {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    if (pendingArgs !== null) {
      fn(...pendingArgs);
      pendingArgs = null;
    }
  };

  return debounced;
}

