const RANGES = { minute:[0,59], hour:[0,23], dayOfMonth:[1,31], month:[1,12], dayOfWeek:[0,6] } as const
type Field = keyof typeof RANGES

const clamp = (v:number,[min,max]:readonly[number,number]) => v>=min && v<=max

const expand = (expr:string,[min,max]:readonly[number,number]):number[] => {
  if(expr==='*') return Array.from({length:max-min+1},(_,i)=>i+min)
  if(expr.startsWith('*/')) {
    const step=+expr.slice(2)
    return Array.from({length:max-min+1},(_,i)=>i+min).filter(v=>((v-min)%step)===0)
  }
  if(expr.includes('-')) {
    const [a,b]=expr.split('-').map(Number)
    if(!clamp(a,[min,max])||!clamp(b,[min,max])||a>b) throw new Error(`Invalid range: ${expr}`)
    return Array.from({length:b-a+1},(_,i)=>i+a)
  }
  if(expr.includes(',')) {
    const vals=expr.split(',').map(Number)
    if(vals.some(v=>!clamp(v,[min,max]))) throw new Error(`Out of range: ${expr}`)
    return [...new Set(vals)].sort((a,b)=>a-b)
  }
  const v=+expr
  if(!clamp(v,[min,max])) throw new Error(`Out of range: ${expr}`)
  return [v]
}

