// A debounce implementation that a tired engineer can follow at 3am.
// We track the timer ID and the last-seen arguments separately so that
// flush() can fire with whatever args were most recently queued.

type AnyFunction = (...args: unknown[]) => unknown;

// Extend the debounced function type with control methods
type Debounced<F extends AnyFunction> = {
  (...args: Parameters<F>): void;
  // cancel: throw away the queued call without running it
  cancel: () => void;
  // flush: run the queued call right now (no-op if nothing is pending)
  flush: () => void;
};

function debounce<F extends AnyFunction>(fn: F, delayMs: number): Debounced<F> {
  // timerId is null when nothing is pending; set when a call is queued
  let timerId: ReturnType<typeof setTimeout> | null = null;

  // We need to remember the most recent args so flush() can use them
  let pendingArgs: Parameters<F> | null = null;

  // The actual debounced wrapper the caller invokes
  const debounced = (...args: Parameters<F>): void => {
    // Store the latest args every time — last write wins
    pendingArgs = args;

    // Clear any previously scheduled invocation; we're resetting the clock
    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      // Timer fired naturally — run the function and clean up state
      timerId = null;
      const argsToUse = pendingArgs!;
      pendingArgs = null;
      fn(...argsToUse);
    }, delayMs);
  };

  // cancel: discard the pending call entirely, leaving state clean
  debounced.cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    // Drop the stored args — the call is gone
    pendingArgs = null;
  };

  // flush: fire immediately if a call is pending, otherwise do nothing.
  // We clear the timer first so the natural timer never double-fires.
  debounced.flush = (): void => {
    if (timerId === null) {
      // Nothing is pending — nothing to do
      return;
    }

    clearTimeout(timerId);
    timerId = null;

    const argsToUse = pendingArgs!;
    pendingArgs = null;

    fn(...argsToUse);
  };

  return debounced;
}

