const RANGES = { minute:[0,59], hour:[0,23], dayOfMonth:[1,31], month:[1,12], dayOfWeek:[0,6] } as const
type Field = keyof typeof RANGES

const all = (f:Field) => Array.from({length:RANGES[f][1]-RANGES[f][0]+1},(_,i)=>i+RANGES[f][0])
const clamp = (v:number,[mn,mx]:[number,number]) => v>=mn&&v<=mx

const parseField = (s:string,f:Field):number[] => {
  const [mn,mx]=RANGES[f]
  if(s==='*') return all(f)
  if(s.includes(',')) return [...new Set(s.split(',').flatMap(p=>parseField(p,f)))].sort((a,b)=>a-b)
  if(s.startsWith('*/')) { const step=+s.slice(2); return all(f).filter(v=>(v-mn)%step===0) }
  if(s.includes('/')) { const [r,step]=s.split('/'); const base=parseField(r,f); return base.filter(v=>(v-base[0])%+step===0) }
  if(s.includes('-')) { const [a,b]=s.split('-').map(Number); if(!clamp(a,[mn,mx])||!clamp(b,[mn,mx])) throw new Error(`Range ${s} out of bounds for ${f}`); return Array.from({length:b-a+1},(_,i)=>a+i) }
  const n=+s; if(isNaN(n)||!clamp(n,[mn,mx])) throw new Error(`Value ${s} out of bounds for ${f}`); return [n]
}

const parseCron = (expr:string) => {
  const [minute,hour,dayOfMonth,month,dayOfWeek]=expr.trim().split(/\s+/)
  if([minute,hour,dayOfMonth,month,dayOfWeek].some(v=>v===undefined)) throw new Error('Invalid cron')
  return { minute:parseField(minute,'minute'), hour:parseField(hour,'hour'), dayOfMonth:parseField(dayOfMonth,'dayOfMonth'), month:parseField(month,'month'), dayOfWeek:parseField(dayOfWeek,'dayOfWeek') }
}

