type Debounced<T extends (...args: any[]) => any> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: any[]) => any>(fn: T, delay: number): Debounced<T> {
  let t: ReturnType<typeof setTimeout> | null = null;
  let pending: Parameters<T> | null = null;

  const d = (...args: Parameters<T>) => {
    pending = args;
    if (t) clearTimeout(t);
    t = setTimeout(() => { fn(...pending!); t = null; pending = null; }, delay);
  };

  d.cancel = () => { if (t) { clearTimeout(t); t = null; pending = null; } };
  d.flush = () => { if (t) { clearTimeout(t); t = null; fn(...pending!); pending = null; } };

  return d;
} // @stance: minimal

type PlainObject = Record<string, unknown>;

const isPlainObject = (value: unknown): value is PlainObject =>
  typeof value === "object" &&
  value !== null &&
  !Array.isArray(value) &&
  Object.getPrototypeOf(value) === Object.prototype;

const mergeValues = (targetValue: unknown, sourceValue: unknown): unknown => {
  if (isPlainObject(targetValue) && isPlainObject(sourceValue))
    return deepMerge(targetValue, sourceValue);

  if (Array.isArray(targetValue) && Array.isArray(sourceValue))
    return [...targetValue, ...sourceValue];

  return sourceValue;
};

const deepMerge = (target: PlainObject, source: PlainObject): PlainObject =>
  Object.keys({ ...target, ...source }).reduce<PlainObject>(
    (mergedAccumulator, key) => ({
      ...mergedAccumulator,
      [key]:
        key in target && key in source
          ? mergeValues(target[key], source[key])
          : key in source
            ? source[key]
            : target[key],
    }),
    {}
  );

