// Checks if a value is a "plain object" — meaning it was created via {} or Object.create(null),
// NOT an array, Date, Map, null, etc. We need this to avoid accidentally merging those things.
function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (typeof value !== "object" || value === null) return false;
  const proto = Object.getPrototypeOf(value);
  // Allow both Object.create(null) (no prototype) and standard {} literals
  return proto === null || proto === Object.prototype;
}

// Recursively merges `source` into `target`, returning a NEW object (no mutation).
// Rules:
//   - both plain objects → recurse
//   - both arrays → concatenate
//   - anything else → source wins
export default function deepMerge(
  target: Record<string, unknown>,
  source: Record<string, unknown>
): Record<string, unknown> {
  // Guard: if either argument is not a plain object, source replaces target outright.
  // This keeps the function honest at the top level — don't silently swallow bad input.
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return isPlainObject(source) ? { ...source } : ({} as Record<string, unknown>);
  }

  // Start with a shallow copy of target so we don't mutate the caller's data.
  // Mutating input at 3am leads to hours of debugging. Explicit copy, always.
  const result: Record<string, unknown> = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      // Both arrays: concatenate. We don't deep-merge array elements —
      // that would require knowing the element identity, which we don't have.
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      // Both plain objects: recurse one level deeper.
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      // Everything else (primitives, mixed types, nulls, Dates, etc.):
      // source wins. Simple and predictable — no surprises at 3am.
      result[key] = sourceVal;
    }
  }

  return result;
}
