type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || value === undefined) return false;
  if (typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function assertPlainObject(value: unknown, label: string): asserts value is PlainObject {
  if (value === null || value === undefined) {
    throw new TypeError(`deepMerge: ${label} must not be null or undefined`);
  }
  if (typeof value !== "object") {
    throw new TypeError(
      `deepMerge: ${label} must be a plain object, received ${typeof value}`
    );
  }
  if (Array.isArray(value)) {
    throw new TypeError(
      `deepMerge: ${label} must be a plain object, received Array`
    );
  }
  const proto = Object.getPrototypeOf(value);
  if (proto !== Object.prototype && proto !== null) {
    throw new TypeError(
      `deepMerge: ${label} must be a plain object, received class instance [${
        (value as object)?.constructor?.name ?? "unknown"
      }]`
    );
  }
}

function mergeValue(targetVal: unknown, sourceVal: unknown): unknown {
  if (sourceVal === undefined) {
    return targetVal;
  }
  if (targetVal === undefined) {
    if (Array.isArray(sourceVal)) {
      return sourceVal.map((item) => (isPlainObject(item) ? deepMergeInternal(Object.create(null), item) : item));
    }
    if (isPlainObject(sourceVal)) {
      return deepMergeInternal(Object.create(null), sourceVal);
    }
    return sourceVal;
  }
  if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
    const safeTarget = targetVal.slice();
    const safeSource = sourceVal.slice();
    return safeTarget.concat(safeSource);
  }
  if (Array.isArray(targetVal) !== Array.isArray(sourceVal)) {
    return Array.isArray(sourceVal) ? sourceVal.slice() : sourceVal;
  }
  if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
    return deepMergeInternal(targetVal, sourceVal);
  }
  return sourceVal;
}

function deepMergeInternal(target: PlainObject, source: PlainObject): PlainObject {
  const result: PlainObject = Object.create(null);

  const targetKeys = Object.keys(target);
  for (let i = 0; i < targetKeys.length; i++) {
    const key = targetKeys[i];
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }
    if (!Object.prototype.hasOwnProperty.call(target, key)) {
      continue;
    }
    result[key] = target[key];
  }

  const sourceKeys = Object.keys(source);
  for (let i = 0; i < sourceKeys.length; i++) {
    const key = sourceKeys[i];
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }
    if (!Object.prototype.hasOwnProperty.call(source, key)) {
      continue;
    }
    result[key] = mergeValue(result[key], source[key]);
  }

  return result;
}

export default function deepMerge(target: unknown, source: unknown): PlainObject {
  assertPlainObject(target, "target");
  assertPlainObject(source, "source");

  if (target === source) {
    return deepMergeInternal(target, Object.create(null));
  }

  return deepMergeInternal(target, source);
}
