const RANGES = { minute:[0,59], hour:[0,23], dayOfMonth:[1,31], month:[1,12], dayOfWeek:[0,6] } as const
type Field = keyof typeof RANGES

const all = (f: Field) => Array.from({length: RANGES[f][1]-RANGES[f][0]+1}, (_,i)=>i+RANGES[f][0])

const clamp = (v: number, [lo,hi]: readonly [number,number]) => v>=lo && v<=hi

const parseField = (s: string, f: Field): number[] => {
  const r = RANGES[f]
  if(s==='*') return all(f)
  if(s.includes(',')) return [...new Set(s.split(',').flatMap(p=>parseField(p,f)))].sort((a,b)=>a-b)
  if(s.startsWith('*/')) {
    const step = +s.slice(2)
    return all(f).filter(v=>(v-r[0])%step===0)
  }
  if(s.includes('/')) {
    const [range,step] = s.split('/')
    const base = parseField(range,f)
    return base.filter((_,i)=>i%+step===0)
  }
  if(s.includes('-')) {
    const [lo,hi] = s.split('-').map(Number)
    return Array.from({length:hi-lo+1},(_,i)=>lo+i).filter(v=>clamp(v,r))
  }
  const n = +s
  return clamp(n,r) ? [n] : []
}

const parseCron = (expr: string): Record<Field, number[]> => {
  const [minute,hour,dayOfMonth,month,dayOfWeek] = expr.trim().split(/\s+/)
  return {
    minute: parseField(minute,'minute'),
    hour: parseField(hour,'hour'),
    dayOfMonth: parseField(dayOfMonth,'dayOfMonth'),
    month: parseField(month,'month'),
    dayOfWeek: parseField(dayOfWeek,'dayOfWeek'),
  }
}

