type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel: () => void;
  flush: () => void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  const flush = (): void => {
    if (timerId !== null && pendingArgs !== null) {
      clearTimeout(timerId);
      timerId = null;
      const args = pendingArgs;
      pendingArgs = null;
      fn(...args);
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = null;
      const invokeArgs = pendingArgs;
      pendingArgs = null;
      if (invokeArgs !== null) {
        fn(...invokeArgs);
      }
    }, delay);
  };

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const fieldOrder: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

const fieldBounds: Record<CronField, readonly [min: number, max: number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

const integerRange = (from: number, to: number): number[] =>
  Array.from({ length: to - from + 1 }, (_, offset) => from + offset);

const assertWithinBounds = (value: number, min: number, max: number, context: string): void => {
  if (value < min || value > max)
    throw new RangeError(`Value ${value} out of bounds [${min}, ${max}] in "${context}"`);
};

const parseWildcardStep = (expression: string, min: number, max: number): number[] => {
  const step = parseInt(expression.slice(2), 10);
  if (isNaN(step) || step <= 0)
    throw new SyntaxError(`Invalid step expression: "${expression}"`);
  return integerRange(min, max).filter(n => (n - min) % step === 0);
};

const parseRangeExpression = (expression: string, min: number, max: number): number[] => {
  const [rawStart, rawEnd] = expression.split("-").map(s => parseInt(s, 10));
  if (isNaN(rawStart) || isNaN(rawEnd) || rawStart > rawEnd)
    throw new SyntaxError(`Invalid range expression: "${expression}"`);
  assertWithinBounds(rawStart, min, max, expression);
  assertWithinBounds(rawEnd,   min, max, expression);
  return integerRange(rawStart, rawEnd);
};

const parseSingleToken = (token: string, min: number, max: number): number[] => {
  if (token === "*")            return integerRange(min, max);
  if (token.startsWith("*/"))   return parseWildcardStep(token, min, max);
  if (token.includes("-"))      return parseRangeExpression(token, min, max);

  const value = parseInt(token, 10);
  if (isNaN(value)) throw new SyntaxError(`Unrecognised cron token: "${token}"`);
  assertWithinBounds(value, min, max, token);
  return [value];
};

const parseFieldExpression = (expression: string, min: number, max: number): number[] => {
  const uniquelySorted = (values: number[]) =>
    [...new Set(values)].sort((a, b) => a - b);

  return uniquelySorted(
    expression
      .split(",")
      .flatMap(token => parseSingleToken(token.trim(), min, max))
  );
};

const parseCron = (cronExpression: string): ParsedCron => {
  const fields = cronExpression.trim().split(/\s+/);

  if (fields.length !== 5)
    throw new SyntaxError(
      `Expected 5 cron fields, received ${fields.length}: "${cronExpression}"`
    );

  return Object.fromEntries(
    fieldOrder.map((field, index) => {
      const [min, max] = fieldBounds[field];
      return [field, parseFieldExpression(fields[index], min, max)];
    })
  ) as ParsedCron;
};

