type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || value === undefined) return false;
  if (typeof value !== "object") return false;
  if (Array.isArray(value)) return false;

  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function isArray(value: unknown): value is unknown[] {
  return Array.isArray(value);
}

function cloneDeep(value: unknown): unknown {
  if (value === null || value === undefined) return value;
  if (typeof value !== "object") return value;

  if (isArray(value)) {
    const result: unknown[] = [];
    for (let i = 0; i < value.length; i++) {
      const item = value[i];
      result.push(cloneDeep(item));
    }
    return result;
  }

  if (isPlainObject(value)) {
    const result: PlainObject = Object.create(null);
    const keys = Object.keys(value);
    for (let i = 0; i < keys.length; i++) {
      const key = keys[i];
      if (key === "__proto__" || key === "constructor" || key === "prototype") {
        continue;
      }
      result[key] = cloneDeep(value[key]);
    }
    return result;
  }

  // Defensively reject exotic objects (Date, Map, Set, RegExp, etc.)
  throw new TypeError(
    `deepMerge: unsupported value type "${Object.prototype.toString.call(value)}" encountered during clone. Only plain objects and arrays are supported.`
  );
}

function mergeObjects(target: PlainObject, source: PlainObject): PlainObject {
  const result: PlainObject = Object.create(null);

  const targetKeys = Object.keys(target);
  for (let i = 0; i < targetKeys.length; i++) {
    const key = targetKeys[i];
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }
    result[key] = cloneDeep(target[key]);
  }

  const sourceKeys = Object.keys(source);
  for (let i = 0; i < sourceKeys.length; i++) {
    const key = sourceKeys[i];
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const targetVal = result[key];
    const sourceVal = source[key];

    if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = mergeObjects(targetVal, sourceVal);
    } else if (isArray(targetVal) && isArray(sourceVal)) {
      const merged: unknown[] = [];
      for (let j = 0; j < targetVal.length; j++) merged.push(cloneDeep(targetVal[j]));
      for (let j = 0; j < sourceVal.length; j++) merged.push(cloneDeep(sourceVal[j]));
      result[key] = merged;
    } else {
      result[key] = cloneDeep(sourceVal);
    }
  }

  return result;
}

export default function deepMerge(target: unknown, source: unknown): PlainObject {
  if (target === null || target === undefined) {
    throw new TypeError(
      `deepMerge: "target" must be a non-null plain object, received ${target === null ? "null" : "undefined"}.`
    );
  }

  if (source === null || source === undefined) {
    throw new TypeError(
      `deepMerge: "source" must be a non-null plain object, received ${source === null ? "null" : "undefined"}.`
    );
  }

  if (!isPlainObject(target)) {
    throw new TypeError(
      `deepMerge: "target" must be a plain object, received "${Object.prototype.toString.call(target)}".`
    );
  }

  if (!isPlainObject(source)) {
    throw new TypeError(
      `deepMerge: "source" must be a plain object, received "${Object.prototype.toString.call(source)}".`
    );
  }

  if (target === source) {
    return cloneDeep(target) as PlainObject;
  }

  return mergeObjects(target, source);
}
