// Field definitions: name, min, max
// These bounds are used for wildcard expansion and range validation.
const CRON_FIELDS = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
] as const;

type FieldName = (typeof CRON_FIELDS)[number]["name"];

export type ParsedCron = Record<FieldName, number[]>;

// Expand a single token (e.g. "*/15", "1-5", "3", "*") into a list of numbers.
// Bounds are passed in so the logic stays generic across all 5 fields.
function expandToken(token: string, min: number, max: number): number[] {
  // Step value: */n or start-end/n
  if (token.includes("/")) {
    const [rangePart, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value in token: "${token}"`);
    }

    // Determine the start of the range.
    // "*" means start from field minimum; a plain number means start there.
    let start = min;
    let end   = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        // e.g. "1-5/2"
        const [s, e] = rangePart.split("-").map(Number);
