  // Range: start-end
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);

    validateRange(start, end, min, max, token);
    if (start > end) {
      throw new Error(`Range start must be <= end in token: "${token}"`);
