type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || value === undefined) return false;
  if (typeof value !== "object") return false;
  if (Array.isArray(value)) return false;

  const proto = Object.getPrototypeOf(value);
  if (proto === null) return true;
  if (proto !== Object.prototype) return false;

  return true;
}

function assertPlainObject(value: unknown, label: string): asserts value is PlainObject {
  if (!isPlainObject(value)) {
    throw new TypeError(
      `deepMerge: expected ${label} to be a plain object, got ${
        value === null ? "null" : Array.isArray(value) ? "array" : typeof value
      }`
    );
  }
}

function deepMergeInner(target: PlainObject, source: PlainObject, depth: number): PlainObject {
  if (depth > 512) {
    throw new RangeError(
      `deepMerge: maximum recursion depth (512) exceeded — possible circular reference`
    );
  }

  const result: PlainObject = Object.create(null);

  const targetKeys = Object.keys(target);
  const sourceKeys = Object.keys(source);

  const allKeys = new Set<string>([...targetKeys, ...sourceKeys]);

  for (const key of allKeys) {
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const hasTarget = Object.prototype.hasOwnProperty.call(target, key);
    const hasSource = Object.prototype.hasOwnProperty.call(source, key);

    if (!hasTarget && !hasSource) {
      continue;
    }

    if (hasTarget && !hasSource) {
      const targetVal = target[key];
      result[key] = isPlainObject(targetVal)
        ? deepMergeInner(targetVal, Object.create(null), depth + 1)
        : Array.isArray(targetVal)
        ? [...(targetVal as unknown[])]
        : targetVal;
      continue;
    }

    if (!hasTarget && hasSource) {
      const sourceVal = source[key];
      result[key] = isPlainObject(sourceVal)
        ? deepMergeInner(Object.create(null), sourceVal, depth + 1)
        : Array.isArray(sourceVal)
        ? [...(sourceVal as unknown[])]
        : sourceVal;
      continue;
    }

    const targetVal = target[key];
    const sourceVal = source[key];

    if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMergeInner(targetVal, sourceVal, depth + 1);
      continue;
    }

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...(targetVal as unknown[]), ...(sourceVal as unknown[])];
      continue;
    }

    result[key] = sourceVal;
  }

  return result;
}

export default function deepMerge(target: unknown, source: unknown): PlainObject {
  if (target === undefined || target === null) {
    throw new TypeError(
      `deepMerge: expected target to be a plain object, got ${target === null ? "null" : "undefined"}`
    );
  }

  if (source === undefined || source === null) {
    throw new TypeError(
      `deepMerge: expected source to be a plain object, got ${source === null ? "null" : "undefined"}`
    );
  }

  assertPlainObject(target, "target");
  assertPlainObject(source, "source");

  return deepMergeInner(target, source, 0);
