type AnyFunction = (...args: Parameters<AnyFunction>) => ReturnType<AnyFunction>;

type Debounced<F extends AnyFunction> = {
  (...args: Parameters<F>): void;
  cancel: () => void;
  flush: () => ReturnType<F> | undefined;
};

const debounce = <F extends AnyFunction>(fn: F, delayMs: number): Debounced<F> => {
  let pendingTimer: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<F> | undefined;

  const cancel = (): void => {
    if (pendingTimer !== undefined) {
      clearTimeout(pendingTimer);
      pendingTimer = undefined;
    }
    pendingArgs = undefined;
  };

  const flush = (): ReturnType<F> | undefined => {
    if (pendingArgs === undefined) return undefined;
    const argsToInvoke = pendingArgs;
    cancel();
    return fn(...argsToInvoke) as ReturnType<F>;
  };

  const scheduleOrReschedule = (...args: Parameters<F>): void => {
    pendingArgs = args;
    if (pendingTimer !== undefined) clearTimeout(pendingTimer);
    pendingTimer = setTimeout(flush, delayMs);
  };

  return Object.assign(scheduleOrReschedule, { cancel, flush });
};

export default debounce;
