// dayOfWeek allows 0–7 where 7 is an alias for 0 (Sunday)
const FIELD_RANGES: Readonly<Record<CronField, FieldRange>> = Object.freeze(
  Object.assign(Object.create(null) as Record<CronField, FieldRange>, {
    minute:     Object.freeze({ min: 0,  max: 59 }),
    hour:       Object.freeze({ min: 0,  max: 23 }),
    dayOfMonth: Object.freeze({ min: 1,  max: 31 }),
    month:      Object.freeze({ min: 1,  max: 12 }),
    dayOfWeek:  Object.freeze({ min: 0,  max: 7  }),
