    throw new TypeError(`[parseCron] No field range registered for "${field}"`);
  }
  if (value < range.min || value > range.max) {
    throw new TypeError(
      `[parseCron] Value ${value} is out of range [${range.min}–${range.max}] for field "${field}"`
    );
