  if (start > end) {
    throw new TypeError(
      `[parseCron] Range start (${start}) must not exceed end (${end}) in field "${field}"`
    );
  }
  assertInFieldRange(start, field);
  assertInFieldRange(end, field);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
