// Recursive helper that walks the object tree, building up a key prefix as it goes.
// We separate this from the public function so callers don't need to pass a prefix.
function flattenRecursive(
  // Using `unknown` instead of `any` so TypeScript forces us to check types
  value: unknown,
  prefix: string,
  result: Record<string, unknown>
): void {
  // Base case: if it's not a plain object (or is null/array), store the value.
  // Arrays are intentionally treated as leaf values — flattening "a.0.b" style
  // keys for arrays is surprising at 3am. Keep it simple.
  if (
    value === null ||
    typeof value !== "object" ||
    Array.isArray(value)
  ) {
    result[prefix] = value;
    return;
  }

  const obj = value as Record<string, unknown>;
  const keys = Object.keys(obj);

  // Edge case: an empty object has no keys to flatten, so store it as-is.
  // Without this, `{ a: {} }` would silently vanish from the output.
  if (keys.length === 0) {
    result[prefix] = obj;
    return;
  }

  for (const key of keys) {
    // Build the dot-notation path. At the top level prefix is "", so we skip
    // the leading dot. At deeper levels we join with ".".
    const nestedKey = prefix === "" ? key : `${prefix}.${key}`;
    flattenRecursive(obj[key], nestedKey, result);
  }
