): Record<string, unknown> {
  // Guard: if someone passes null/undefined at runtime, return empty object
  // rather than throwing. Easier to trace than an unexpected crash.
  if (input === null || input === undefined || typeof input !== "object") {
    return {};
  }

  const result: Record<string, unknown> = {};
  // Start with an empty prefix — the recursive helper will build keys from here
  flattenRecursive(input, "", result);
  return result;
}
