}

// Parse a single segment like "5", "*", "*/15", "1-5", "1,3,5".
// Returns the set of valid integer values the segment represents.
function parseSegment(segment: string, fieldMin: number, fieldMax: number): number[] {
  // Comma-separated list: split and recurse.
  // We check this first so "1,3,5" doesn't confuse the step/range parsers.
  if (segment.includes(",")) {
    const parts = segment.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      // Each part is itself a valid segment (number, range, step, or wildcard)
      for (const v of parseSegment(part.trim(), fieldMin, fieldMax)) {
        values.add(v);
