    let rangeMin = fieldMin;
    let rangeMax = fieldMax;

    if (base !== "*") {
      // Base is a range like "0-30"
      const rangeParts = parseRange(base, fieldMin, fieldMax);
      rangeMin = rangeParts[0];
      rangeMax = rangeParts[1];
