    throw new Error(`Range start ${lo} is greater than end ${hi} in: "${segment}"`);
  }

  validateBounds(lo, fieldMin, fieldMax, segment);
  validateBounds(hi, fieldMin, fieldMax, segment);

  return [lo, hi];
