const FIELD_BOUNDS: Record<CronField, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   7],
};

const FIELD_ORDER: CronField[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

const clampedRange = (from: number, to: number, step = 1): number[] =>
  Array.from(
    { length: Math.floor((to - from) / step) + 1 },
    (_, i) => from + i * step,
