const validateBounds = (value: number, [min, max]: [number, number], raw: string): number => {
  if (value < min || value > max)
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in segment "${raw}"`);
  return value;
};

const parseSegment = (segment: string, field: CronField): number[] => {
  const [min, max] = FIELD_BOUNDS[field];
  const fullRange = clampedRange(min, max);

  if (segment === "*") return fullRange;

  if (segment.includes(","))
    return segment
      .split(",")
      .flatMap(part => parseSegment(part.trim(), field))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);

