  if (segment.includes("-")) {
    const [rawFrom, rawTo] = segment.split("-").map(n => parseInt(n, 10));
    const from = validateBounds(rawFrom, [min, max], segment);
    const to   = validateBounds(rawTo,   [min, max], segment);
    if (from > to)
      throw new RangeError(`Range start ${from} exceeds end ${to} in "${segment}"`);
