  const value = parseInt(segment, 10);
  if (isNaN(value))
    throw new TypeError(`Unrecognised cron token "${segment}" for field "${field}"`);

  // dayOfWeek: normalise sunday-as-7 → 0
  const normalised = field === "dayOfWeek" && value === 7 ? 0 : value;
  validateBounds(normalised, [min, max], segment);
