function flattenRecursive(
  input: NestedObject,
  prefix: string,
  result: FlatObject
): void {
  for (const key of Object.keys(input)) {
    // Build the full dot-notation key for this property.
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = input[key];

    // WHY this exact condition:
    //   Arrays are typeof "object" too, but we don't want to flatten
    //   ["x", "y"] into "arr.0", "arr.1" — that would surprise most callers.
    //   null is also typeof "object" so we guard against that explicitly.
