interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(
  expression: string,
  fieldName: keyof CronFields
): number[] {
  const { min, max } = FIELD_RANGES[fieldName];
  const fullRange = Array.from({ length: max - min + 1 }, (_, i) => i + min);

  // Handle comma-separated lists by splitting and recursively parsing each part
  if (expression.includes(",")) {
    const parts = expression.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), fieldName)) {
        values.add(v);
      }
