    return Array.from(values).sort((a, b) => a - b);
  }

  // Wildcard
  if (expression === "*") {
    return fullRange;
  }

  // Step value: */step or start-end/step
  if (expression.includes("/")) {
    const [rangePart, stepStr] = expression.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in expression: "${expression}"`);
    }

    let rangeValues: number[];

    if (rangePart === "*") {
      rangeValues = fullRange;
    } else if (rangePart.includes("-")) {
      rangeValues = parseRangePart(rangePart, min, max);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) {
        throw new Error(`Invalid expression: "${expression}"`);
      }
      clamp(start, min, max);
      rangeValues = Array.from(
        { length: Math.floor((max - start) / step) + 1 },
        (_, i) => start + i * step
      ).filter((v) => v <= max);
      return rangeValues;
    }

    return rangeValues.filter((_, i) => i % step === 0);
  }

  // Range: start-end
  if (expression.includes("-")) {
    return parseRangePart(expression, min, max);
  }

  // Single number
  const num = parseInt(expression, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid cron field value: "${expression}"`);
  }
  clamp(num, min, max);
  return [num];
}

function parseRangePart(
  expression: string,
  min: number,
  max: number
): number[] {
  const [startStr, endStr] = expression.split("-");
  const start = parseInt(startStr, 10);
  const end = parseInt(endStr, 10);

  if (isNaN(start) || isNaN(end)) {
    throw new Error(`Invalid range expression: "${expression}"`);
  }

  if (start > end) {
    throw new RangeError(
      `Range start ${start} is greater than end ${end} in expression: "${expression}"`
    );
