//     original signature instead of collapsing to `(...args: unknown[]) => void`.
//   - `flush()` returns the same type as the wrapped function so callers can
//     use the return value when flushing eagerly.
//   - We clear pendingArgs after flush/cancel so a second flush is a no-op,
//     not a surprise double-call.

type AnyFunction = (...args: unknown[]) => unknown;

// The debounced function keeps the original parameter signature but always
// returns void — the real return value is only available via flush().
type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): ReturnType<T> | undefined;
};

function debounce<T extends AnyFunction>(
  fn: T,
  delayMs: number
): DebouncedFunction<T> {
  // State lives in closure — one timer handle and one snapshot of the last
  // arguments seen. Both start empty.
  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  // The core debounced function. Each call resets the timer window.
  const debounced = (...args: Parameters<T>): void => {
    // Remember the latest arguments — flush() will use these.
    pendingArgs = args;

    // Clear any existing timer so the delay always counts from the *latest* call.
    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      // Timer fired naturally — invoke with whatever args we last saw.
      if (pendingArgs !== null) {
        fn(...pendingArgs);
      }
      // Clean up so a subsequent flush() is a safe no-op.
      timerId = null;
      pendingArgs = null;
