  // Cancel drops the timer and forgets the pending args entirely.
  // After cancel(), flush() will return undefined and do nothing.
  debounced.cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;
  };

  // Flush fires the pending call *right now*, bypassing the remaining delay.
  // Returns the wrapped function's return value so callers aren't surprised
  // when they need it (e.g., a save that returns a Promise).
  // If there is nothing pending, returns undefined — callers should guard
  // against this if they depend on the return value.
  debounced.flush = (): ReturnType<T> | undefined => {
    // No pending call — nothing to do.
    if (pendingArgs === null) {
      return undefined;
    }

    // Capture args before we clear state, so the call below sees the right values.
    const argsToInvoke = pendingArgs;

    // Tear down timer and state *before* calling fn in case fn itself calls
    // the debounced function (re-entrancy guard).
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;

    return fn(...argsToInvoke) as ReturnType<T>;
  };

  return debounced;
}

