    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value "${stepPart}" in field "${fieldName}"`);
    }

    // Figure out the start/end for the base
    let start: number;
    let end: number;

    if (basePart === "*") {
      // "*/15" means every 15 from the field's minimum
      start = min;
      end = max;
    } else if (basePart.includes("-")) {
      [start, end] = parseRange(basePart, fieldName);
    } else {
      // A bare number as base: "5/10" means start at 5, step by 10
      start = parseInt(basePart, 10);
      end = max;
      if (isNaN(start)) {
        throw new Error(`Invalid step base "${basePart}" in field "${fieldName}"`);
      }
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: "9-17"
  if (token.includes("-")) {
    const [start, end] = parseRange(token, fieldName);
    const values: number[] = [];
    for (let i = start; i <= end; i++) {
      values.push(i);
    }
    return values;
  }

  // Wildcard: "*" — expand to every value in the field's range
  if (token === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) {
      values.push(i);
    }
    return values;
  }

  // Plain number: "5"
  const value = parseInt(token, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value "${token}" in field "${fieldName}"`);
  }
  return [value];
}

// Parse "start-end" and validate both numbers are in range
function parseRange(token: string, fieldName: FieldName): [number, number] {
  const { min, max } = FIELD_RANGES[fieldName];
  const [startStr, endStr] = token.split("-");
  const start = parseInt(startStr, 10);
  const end = parseInt(endStr, 10);

  if (isNaN(start) || isNaN(end)) {
    throw new Error(`Invalid range "${token}" in field "${fieldName}"`);
  }
  if (start > end) {
    throw new Error(`Range start ${start} > end ${end} in field "${fieldName}"`);
  }
  if (start < min || end > max) {
    throw new Error(
      `Range "${token}" is outside valid bounds [${min}-${max}] for field "${fieldName}"`
    );
  }

  return [start, end];
}

// Validate that every value in an expanded array is within the field's allowed range
// Done after expansion so a "*/15" in minute doesn't accidentally produce 75
function validateValues(values: number[], fieldName: FieldName): void {
  const { min, max } = FIELD_RANGES[fieldName];
  for (const v of values) {
    if (v < min || v > max) {
      throw new Error(
        `Value ${v} is out of range [${min}-${max}] for field "${fieldName}"`
      );
    }
  }
}

// Main exported function — takes a 5-field cron string, returns structured object
export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  // Split on whitespace — allows multiple spaces between fields
  const tokens = expression.trim().split(/\s+/);

  if (tokens.length !== 5) {
    throw new Error(
      `Expected 5 cron fields, got ${tokens.length}. Input: "${expression}"`
    );
  }

  // Build result by expanding each token for its corresponding field
  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const token = tokens[i];

    const values = expandSegment(token, fieldName);

    // Extra safety net: confirm every expanded value is actually in bounds
    validateValues(values, fieldName);

    result[fieldName] = values;
  }

  return result;
}
// @stance: steady

// Checks if a value is a "plain object" — meaning it was created via
// object literal or Object.create(null), not an Array, Date, null, etc.
// We need this distinction because arrays and dates need different merge
// strategies and instanceof checks alone miss Object.create(null) objects.
function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (typeof value !== "object" || value === null) return false;
  const proto = Object.getPrototypeOf(value);
  // Accept both Object.create(null) (proto === null) and plain {}
  return proto === null || proto === Object.prototype;
}

// Recursively merge `source` into `target`, returning a new object.
// We never mutate the inputs — callers shouldn't have to think about
// whether their objects were clobbered.
export default function deepMerge(
  target: Record<string, unknown>,
  source: Record<string, unknown>
): Record<string, unknown> {
  // Guard: if either argument isn't a plain object, bail out early.
  // Returning target (or source) as a fallback is safer than throwing
  // at 3am when someone passes undefined by accident.
  if (!isPlainObject(target)) return isPlainObject(source) ? { ...source } : {};
  if (!isPlainObject(source)) return { ...target };

  // Start with a shallow copy of target so we don't mutate the original.
  const result: Record<string, unknown> = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      // Both sides are arrays — concatenate rather than overwrite.
      // Spread into a new array so neither original is mutated.
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      // Both sides are plain objects — recurse so nested keys are merged
      // rather than the whole sub-object being replaced.
      result[key] = deepMerge(
        targetVal as Record<string, unknown>,
        sourceVal as Record<string, unknown>
      );
    } else {
      // Everything else: numbers, strings, Dates, null, mismatched types.
      // Source wins — simpler to reason about than coercing types.
      result[key] = sourceVal;
    }
  }

  return result;
}
// @stance: steady

// Recursive flatten: walks every key at the current level,
// builds a dot-notation prefix, and writes leaf values.
// We treat arrays as leaves (not drilling into indices)
// because dot-notation keys like "a.0.b" surprise most callers at 3am.
function flattenObject(
  input: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const key of Object.keys(input)) {
    // Guard: skip inherited properties just in case caller passes something odd
    if (!Object.prototype.hasOwnProperty.call(input, key)) continue;

    const value = input[key];
    // Build the next prefix — no leading dot on the first level
    const fullKey = prefix ? `${prefix}.${key}` : key;

    const isPlainObject =
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp);

    if (isPlainObject) {
      // Drill deeper; pass result through so we accumulate into one object
      flattenObject(value as Record<string, unknown>, fullKey, result);
    } else {
      // Leaf: null, primitives, arrays, Date, RegExp — write it as-is
      result[fullKey] = value;
    }
  }

  return result;
}

export default flattenObject;
// @stance: steady

const FIELD_BOUNDS: Record<string, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;
type FieldName = typeof FIELD_NAMES[number];
type CronResult = Record<FieldName, number[]>;

const clampedRange = (min: number, max: number): number[] =>
  Array.from({ length: max - min + 1 }, (_, i) => i + min);

const guardBounds = (value: number, min: number, max: number, field: string): number => {
  if (value < min || value > max)
    throw new RangeError(`Value ${value} out of bounds [${min}, ${max}] for field "${field}"`);
  return value;
};

const parseWildcard = (min: number, max: number): number[] =>
  clampedRange(min, max);

const parseStep = (base: string, step: number, min: number, max: number, field: string): number[] => {
  const start = base === "*" ? min : guardBounds(parseInt(base, 10), min, max, field);
  if (step <= 0) throw new RangeError(`Step must be positive in field "${field}"`);
  return clampedRange(start, max).filter(v => (v - start) % step === 0);
};

const parseRange = (rawFrom: string, rawTo: string, min: number, max: number, field: string): number[] => {
  const from = guardBounds(parseInt(rawFrom, 10), min, max, field);
  const to   = guardBounds(parseInt(rawTo,   10), min, max, field);
  if (from > to) throw new RangeError(`Range start ${from} exceeds end ${to} in field "${field}"`);
  return clampedRange(from, to);
};

const parseSingleToken = (token: string, min: number, max: number, field: string): number[] => {
  if (token === "*") return parseWildcard(min, max);

  if (token.includes("/")) {
    const [base, stepStr] = token.split("/");
    return parseStep(base, parseInt(stepStr, 10), min, max, field);
  }

  if (token.includes("-")) {
    const [from, to] = token.split("-");
    return parseRange(from, to, min, max, field);
  }

  return [guardBounds(parseInt(token, 10), min, max, field)];
};

const deduplicatedSortedUnion = (arrays: number[][]): number[] =>
  [...new Set(arrays.flat())].sort((a, b) => a - b);

const parseField = (expression: string, field: string): number[] => {
  const [min, max] = FIELD_BOUNDS[field];
  const resolvedTokens = expression.split(",").map(token =>
    parseSingleToken(token.trim(), min, max, field)
  );
  return deduplicatedSortedUnion(resolvedTokens);
};

const parseCron = (cronExpression: string): CronResult => {
  const fields = cronExpression.trim().split(/\s+/);

  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, received ${fields.length}: "${cronExpression}"`);

  return FIELD_NAMES.reduce<CronResult>(
    (result, name, index) => ({ ...result, [name]: parseField(fields[index], name) }),
    {} as CronResult
  );
};

export default parseCron;
// @stance: creative

type Primitive = string | number | boolean | null | undefined;

type FlattenedObject = Record<string, Primitive>;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<Primitive | NestedObject>;
};

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
      return result;
    }
    obj.forEach((item, index) => {
      const key = prefix ? `${prefix}.${index}` : `${index}`;
      if (item !== null && typeof item === "object") {
        flattenObject(item as NestedObject, key, result);
      } else {
        result[key] = item as Primitive;
      }
    });
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object") {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

type DebouncedFunction<T extends (...args: Parameters<T>) => ReturnType<T>> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: Parameters<T>) => ReturnType<T>>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;

  const invoke = (): void => {
    if (pendingArgs !== undefined) {
      const args = pendingArgs;
      pendingArgs = undefined;
      fn(...args);
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      invoke();
    }, delay);
  };

  debounced.cancel = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
  };

  debounced.flush = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    invoke();
  };

  return debounced;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronResult;

interface FieldMeta {
  readonly min: number;
  readonly max: number;
}

const FIELD_META: Readonly<Record<FieldName, FieldMeta>> = Object.freeze(
  Object.assign(Object.create(null) as Record<FieldName, FieldMeta>, {
    minute:     Object.freeze({ min: 0,  max: 59 }),
    hour:       Object.freeze({ min: 0,  max: 23 }),
    dayOfMonth: Object.freeze({ min: 1,  max: 31 }),
    month:      Object.freeze({ min: 1,  max: 12 }),
    dayOfWeek:  Object.freeze({ min: 0,  max: 7  }),
  })
);

const FIELD_ORDER: readonly FieldName[] = Object.freeze([
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
]);

function assertSafeInteger(value: unknown, label: string): asserts value is number {
  if (typeof value !== "number") {
    throw new TypeError(`[parseCron] ${label} must be a number, got ${typeof value}`);
  }
  if (!Number.isFinite(value)) {
    throw new TypeError(`[parseCron] ${label} must be finite, got ${value}`);
  }
  if (!Number.isSafeInteger(value)) {
    throw new TypeError(`[parseCron] ${label} must be a safe integer, got ${value}`);
  }
}

function parseRawInteger(raw: string, label: string): number {
  if (typeof raw !== "string") {
    throw new TypeError(`[parseCron] ${label} token must be a string, got ${typeof raw}`);
  }
  const trimmed = raw.trim();
  if (trimmed.length === 0) {
    throw new TypeError(`[parseCron] ${label} token is empty`);
  }
  if (!/^\d+$/.test(trimmed)) {
    throw new TypeError(`[parseCron] ${label} token "${trimmed}" is not a non-negative integer`);
  }
  const parsed = Number(trimmed);
  assertSafeInteger(parsed, `${label} parsed value`);
  return parsed;
}

function assertInRange(value: number, meta: FieldMeta, context: string): void {
  if (value < meta.min || value > meta.max) {
    throw new RangeError(
      `[parseCron] ${context} value ${value} is out of range [${meta.min}, ${meta.max}]`
    );
  }
}

function expandAll(meta: FieldMeta): number[] {
  const result: number[] = [];
  for (let i = meta.min; i <= meta.max; i++) {
    result.push(i);
  }
  if (result.length === 0) {
    throw new RangeError(`[parseCron] expandAll produced empty range for meta ${JSON.stringify(meta)}`);
  }
  return result;
}

function expandStep(token: string, meta: FieldMeta, fieldName: string): number[] {
  if (typeof token !== "string" || token.trim().length === 0) {
    throw new TypeError(`[parseCron] step token for "${fieldName}" must be a non-empty string`);
  }
  const parts = token.split("/");
  if (parts.length !== 2) {
    throw new TypeError(`[parseCron] step token "${token}" for "${fieldName}" must have exactly one "/"`);
  }
  const [basePart, stepPart] = parts;
  if (basePart == null || stepPart == null) {
    throw new TypeError(`[parseCron] step token "${token}" for "${fieldName}" produced null parts`);
  }

  let rangeMin: number;
  let rangeMax: number;

  if (basePart.trim() === "*") {
    rangeMin = meta.min;
    rangeMax = meta.max;
  } else if (basePart.includes("-")) {
    const rangeParts = basePart.split("-");
    if (rangeParts.length !== 2) {
      throw new TypeError(`[parseCron] step range base "${basePart}" for "${fieldName}" must have exactly one "-"`);
    }
    rangeMin = parseRawInteger(rangeParts[0]!, `${fieldName} step-range start`);
    rangeMax = parseRawInteger(rangeParts[1]!, `${fieldName} step-range end`);
    assertInRange(rangeMin, meta, `${fieldName} step-range start`);
    assertInRange(rangeMax, meta, `${fieldName} step-range end`);
    if (rangeMin > rangeMax) {
      throw new RangeError(
        `[parseCron] step range start ${rangeMin} > end ${rangeMax} in "${fieldName}"`
      );
    }
  } else {
    rangeMin = parseRawInteger(basePart, `${fieldName} step base`);
    assertInRange(rangeMin, meta, `${fieldName} step base`);
    rangeMax = meta.max;
  }

  const step = parseRawInteger(stepPart, `${fieldName} step value`);
  if (step <= 0) {
    throw new RangeError(`[parseCron] step value for "${fieldName}" must be > 0, got ${step}`);
  }

  const result: number[] = [];
  for (let i = rangeMin; i <= rangeMax; i += step) {
    result.push(i);
  }
  if (result.length === 0) {
    throw new RangeError(`[parseCron] step expansion for "${fieldName}" produced empty array`);
  }
  return result;
}

function expandRange(token: string, meta: FieldMeta, fieldName: string): number[] {
  if (typeof token !== "string" || token.trim().length === 0) {
    throw new TypeError(`[parseCron] range token for "${fieldName}" must be a non-empty string`);
  }
  const parts = token.split("-");
  if (parts.length !== 2) {
    throw new TypeError(`[parseCron] range token "${token}" for "${fieldName}" must have exactly one "-"`);
  }
  const lo = parseRawInteger(parts[0]!, `${fieldName} range start`);
  const hi = parseRawInteger(parts[1]!, `${fieldName} range end`);
  assertInRange(lo, meta, `${fieldName} range start`);
  assertInRange(hi, meta, `${fieldName} range end`);
  if (lo > hi) {
    throw new RangeError(
      `[parseCron] range start ${lo} > end ${hi} in field "${fieldName}"`
    );
  }
  const result: number[] = [];
  for (let i = lo; i <= hi; i++) {
    result.push(i);
  }
  if (result.length === 0) {
    throw new RangeError(`[parseCron] range expansion for "${fieldName}" produced empty array`);
  }
  return result;
}

function expandSingleToken(token: string, meta: FieldMeta, fieldName: string): number[] {
  if (typeof token !== "string") {
    throw new TypeError(`[parseCron] token for "${fieldName}" must be a string, got ${typeof token}`);
  }
  const trimmed = token.trim();
  if (trimmed.length === 0) {
    throw new TypeError(`[parseCron] token for "${fieldName}" is empty after trimming`);
  }

  if (trimmed === "*") {
    return expandAll(meta);
  }

  if (trimmed.includes("/")) {
    return expandStep(trimmed, meta, fieldName);
  }

  if (trimmed.includes("-")) {
    return expandRange(trimmed, meta, fieldName);
  }

  const value = parseRawInteger(trimmed, fieldName);
  assertInRange(value, meta, fieldName);
  return [value];
}

function expandField(raw: string, meta: FieldMeta, fieldName: string): number[] {
  if (typeof raw !== "string") {
    throw new TypeError(`[parseCron] field "${fieldName}" must be a string, got ${typeof raw}`);
  }
  const trimmed = raw.trim();
  if (trimmed.length === 0) {
    throw new TypeError(`[parseCron] field "${fieldName}" is empty`);
  }

  const listParts = trimmed.split(",");
  if (!Array.isArray(listParts) || listParts.length === 0) {
    throw new TypeError(`[parseCron] splitting field "${fieldName}" by comma yielded no parts`);
  }

  const seen = new Set<number>();
  const result: number[] = [];

  for (let i = 0; i < listParts.length; i++) {
    const part = listParts[i];
    if (part == null) {
      throw new TypeError(`[parseCron] null element at index ${i} in field "${fieldName}" list`);
    }
    const expanded = expandSingleToken(part, meta, `${fieldName}[${i}]`);
    if (!Array.isArray(expanded)) {
      throw new TypeError(`[parseCron] expansion of "${fieldName}[${i}]" did not return an array`);
    }
    for (const v of expanded) {
      assertSafeInteger(v, `${fieldName}[${i}] expanded value`);
      if (!seen.has(v)) {
        seen.add(v);
        result.push(v);
      }
    }
  }

  result.sort((a, b) => a - b);

  if (result.length === 0) {
    throw new RangeError(`[parseCron] field "${fieldName}" resolved to an empty value set`);
  }

  return result;
}

export default function parseCron(expression: unknown): CronResult {
  if (expression === null || expression === undefined) {
    throw new TypeError(`[parseCron] expression must be a non-empty string, got ${expression}`);
  }
  if (typeof expression !== "string") {
    throw new TypeError(`[parseCron] expression must be a string, got ${typeof expression}`);
  }
  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new TypeError("[parseCron] expression must not be empty or whitespace-only");
  }

  const fields = trimmed.split(/\s+/);
  if (!Array.isArray(fields)) {
    throw new TypeError("[parseCron] splitting expression by whitespace did not yield an array");
  }
  if (fields.length !== 5) {
    throw new TypeError(
      `[parseCron] expression must have exactly 5 fields, got ${fields.length}: "${trimmed}"`
    );
  }

  const result = Object.create(null) as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    if (fieldName == null) {
      throw new TypeError(`[parseCron] FIELD_ORDER[${i}] is unexpectedly null`);
    }
    const raw = fields[i];
    if (raw == null) {
      throw new TypeError(`[parseCron] fields[${i}] is unexpectedly null for field "${fieldName}"`);
    }
    const meta = FIELD_META[fieldName];
    if (meta == null) {
      throw new TypeError(`[parseCron] no metadata found for field "${fieldName}"`);
    }
    result[fieldName] = expandField(raw, meta, fieldName);
  }

  if (
    !Array.isArray(result.minute) ||
    !Array.isArray(result.hour) ||
    !Array.isArray(result.dayOfMonth) ||
    !Array.isArray(result.month) ||
    !Array.isArray(result.dayOfWeek)
  ) {
    throw new TypeError("[parseCron] internal error: result object is missing required array fields");
  }

  return result;
}
// @stance: paranoid

// Recursive flattener — we walk the tree depth-first and build up a
// dot-separated key prefix as we descend. When we hit a leaf (non-plain-object
// value), we write the accumulated key into the result map.
//
// WHY a helper with a prefix param instead of merging results?
// Merging intermediate objects on every recursion allocates O(n log n) extra
// objects. A single shared result map that we mutate during traversal is
// cheaper and easier to follow at 3am.

type PlainObject = Record<string, unknown>;
type FlatObject = Record<string, unknown>;

// Returns true only for plain `{}` style objects.
// Arrays, Dates, null, etc. are treated as leaf values — flattening an array
// into indexed keys ("a.0", "a.1") is almost never what callers want, so we
// leave arrays intact.
function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    Object.getPrototypeOf(value) === Object.prototype
  );
}

function flattenInto(
  node: PlainObject,
  prefix: string,
  result: FlatObject
): void {
  for (const key of Object.keys(node)) {
    // Dot-notation key: prepend the prefix we have so far, or use the key
    // alone when we are at the top level (prefix is empty).
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = node[key];

    if (isPlainObject(value)) {
      // Descend — nothing to write yet, just extend the prefix.
      flattenInto(value, fullKey, result);
    } else {
      // Leaf value (primitive, array, Date, null, etc.) — write it out.
      result[fullKey] = value;
    }
  }
}

