type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      flattenObject(value as unknown as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

export type CronExpression = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldBounds = Readonly<{ min: number; max: number }>;

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

const FIELD_BOUNDS: Record<keyof CronExpression, FieldBounds> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const rangeOf = (start: number, end: number, step = 1): number[] =>
  Array.from(
    { length: Math.floor((end - start) / step) + 1 },
    (_, i) => start + i * step,
  );

const clampedInt = (raw: string, bounds: FieldBounds, fieldName: string): number => {
  const n = parseInt(raw, 10);
  if (isNaN(n))               throw new SyntaxError(`Non-numeric value "${raw}" in field "${fieldName}"`);
  if (n < bounds.min || n > bounds.max)
    throw new RangeError(`Value ${n} out of bounds [${bounds.min}–${bounds.max}] in "${fieldName}"`);
  return n;
};

const resolveRangePart = (
  part: string,
  bounds: FieldBounds,
  fieldName: string,
): [number, number] => {
  if (part === "*") return [bounds.min, bounds.max];
  if (part.includes("-")) {
    const [lo, hi] = part.split("-").map(s => clampedInt(s, bounds, fieldName));
    if (lo > hi) throw new RangeError(`Inverted range ${lo}-${hi} in "${fieldName}"`);
    return [lo, hi];
  }
  const n = clampedInt(part, bounds, fieldName);
  return [n, bounds.max];
};

const expandToken = (token: string, bounds: FieldBounds, fieldName: string): number[] => {
  if (token === "*") return rangeOf(bounds.min, bounds.max);

  if (token.includes("/")) {
    const slashIndex = token.lastIndexOf("/");
    const rangePart  = token.slice(0, slashIndex);
    const stepStr    = token.slice(slashIndex + 1);
    const step       = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1)
      throw new SyntaxError(`Invalid step "${stepStr}" in "${fieldName}"`);
    const [start, end] = resolveRangePart(rangePart, bounds, fieldName);
    return rangeOf(start, end, step);
  }

  if (token.includes("-")) {
    const [start, end] = resolveRangePart(token, bounds, fieldName);
    return rangeOf(start, end);
  }

  return [clampedInt(token, bounds, fieldName)];
};

const parseField = (raw: string, bounds: FieldBounds, fieldName: string): number[] => {
  const expanded = raw
    .split(",")
    .flatMap(token => expandToken(token.trim(), bounds, fieldName));

  return [...new Set(expanded)].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronExpression => {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new SyntaxError(`Cron requires exactly 5 fields; received ${fields.length}`);

  return Object.fromEntries(
    FIELD_NAMES.map((name, i) => [
      name,
      parseField(fields[i], FIELD_BOUNDS[name], name),
    ]),
  ) as CronExpression;
};

