  input: NestedObject,
  prefix: string = ""
): FlattenedObject =>
  Object.entries(input).reduce<FlattenedObject>((accumulator, [key, value]) => {
    const qualifiedKey = prefix ? `${prefix}.${key}` : key;

    return isTraversable(value)
      ? { ...accumulator, ...flattenObject(value, qualifiedKey) }
      : { ...accumulator, [qualifiedKey]: value as Primitive };
