const RANGES = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
} as const;

type Field = keyof typeof RANGES;

const parseField = (expr: string, min: number, max: number): number[] => {
  if (expr === "*") return Array.from({ length: max - min + 1 }, (_, i) => i + min);

  if (expr.includes(",")) return expr.split(",").flatMap(e => parseField(e, min, max));

  if (expr.startsWith("*/")) {
    const step = +expr.slice(2);
    return Array.from({ length: max - min + 1 }, (_, i) => i + min).filter(v => (v - min) % step === 0);
  }

  if (expr.includes("/")) {
    const [range, step] = expr.split("/");
    const [lo, hi] = range === "*" ? [min, max] : range.split("-").map(Number);
    return Array.from({ length: hi - lo + 1 }, (_, i) => i + lo).filter(v => (v - lo) % +step === 0);
  }

  if (expr.includes("-")) {
    const [lo, hi] = expr.split("-").map(Number);
    return Array.from({ length: hi - lo + 1 }, (_, i) => i + lo);
  }

  const v = +expr;
  if (v < min || v > max) throw new RangeError(`${v} out of range [${min},${max}]`);
  return [v];
};

const parseCron = (cron: string): Record<Field, number[]> => {
  const parts = cron.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error("Expected 5 fields");
  const fields = Object.keys(RANGES) as Field[];
  return Object.fromEntries(
    fields.map((f, i) => [f, parseField(parts[i], RANGES[f][0], RANGES[f][1])])
  ) as Record<Field, number[]>;
};

