// A debounced function needs more than just the timer handle —
// we need to remember the last args so flush() can replay them.
type DebouncedFn<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel: () => void;
  flush: () => void;
};

function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delayMs: number
): DebouncedFn<T> {
  // These are closed over — mutable state that persists across calls.
  let timerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  // The actual debounced wrapper.
  // Every call resets the timer so rapid calls collapse into one.
  const debounced = (...args: Parameters<T>): void => {
    // Always save the latest args — we want the most recent call to win.
    pendingArgs = args;

    // Clear any existing timer before starting a new one.
    // This is what makes it "debounce" rather than "throttle".
    if (timerId !== null) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      // Timer fired naturally — invoke with the latest args and clean up.
      const argsToCall = pendingArgs;
      timerId = null;
      pendingArgs = null;

      if (argsToCall !== null) {
        fn(...argsToCall);
      }
    }, delayMs);
  };

  // Cancel stops any pending invocation without calling the function.
  // Safe to call even if nothing is pending.
  debounced.cancel = (): void => {
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    // Drop the pending args so a stale flush() after cancel() is a no-op.
    pendingArgs = null;
  };

  // Flush invokes immediately if there is a pending call,
  // then clears state so the timer can't fire again later.
  debounced.flush = (): void => {
    // Nothing pending — nothing to do. This is intentionally a no-op
    // rather than throwing, because flush() is often called defensively.
    if (pendingArgs === null) {
      return;
    }

    // Capture before clearing, in case fn() somehow triggers another call.
    const argsToCall = pendingArgs;

    // Clear state before invoking to prevent double-fire if the timer
    // somehow expires in the same tick (JS is single-threaded, but
    // being explicit here costs nothing and avoids surprises).
    if (timerId !== null) {
      clearTimeout(timerId);
      timerId = null;
    }
    pendingArgs = null;

    fn(...argsToCall);
  };

  return debounced;
}

export default debounce;
