type AnyFunction = (...args: unknown[]) => unknown;

interface DebouncedFunction<T extends AnyFunction> {
  (...args: Parameters<T>): void;
  cancel: () => void;
  flush: () => void;
}

function debounce<T extends AnyFunction>(fn: T, delay: number): DebouncedFunction<T> {
  if (typeof fn !== "function") {
    throw new TypeError(
      `debounce: expected first argument to be a function, got ${typeof fn}`
    );
  }

  if (typeof delay !== "number") {
    throw new TypeError(
      `debounce: expected second argument to be a number, got ${typeof delay}`
    );
  }

  if (!Number.isFinite(delay)) {
    throw new TypeError(
      `debounce: delay must be a finite number, got ${delay}`
    );
  }

  if (delay < 0) {
    throw new TypeError(
      `debounce: delay must be non-negative, got ${delay}`
    );
  }

  const state = Object.create(null) as {
    timerId: ReturnType<typeof setTimeout> | null;
    pendingArgs: Parameters<T> | null;
  };

  state.timerId = null;
  state.pendingArgs = null;

  const clearPending = (): void => {
    if (state.timerId !== null) {
      clearTimeout(state.timerId);
      state.timerId = null;
    }
  };

  const invokePending = (): void => {
    if (state.pendingArgs === null) {
      return;
    }

    const argsToInvoke = state.pendingArgs;
    state.pendingArgs = null;

    clearPending();

    try {
      fn(...argsToInvoke);
    } catch (err: unknown) {
      throw err instanceof Error
        ? err
        : new Error(
            `debounce: wrapped function threw a non-Error value: ${String(err)}`
          );
    }
  };

  const debounced = function (...args: Parameters<T>): void {
    if (!Array.isArray(args)) {
      throw new TypeError(
        `debounce: expected args to be array-like, received ${typeof args}`
      );
    }

    state.pendingArgs = args;

    clearPending();

    state.timerId = setTimeout(() => {
      state.timerId = null;
      invokePending();
    }, delay);
  } as DebouncedFunction<T>;

  debounced.cancel = (): void => {
    clearPending();
    state.pendingArgs = null;
  };

  debounced.flush = (): void => {
    if (state.pendingArgs === null) {
      return;
    }

    invokePending();
  };

  Object.defineProperty(debounced, "name", {
    value: `debounced(${fn.name ?? "anonymous"})`,
    configurable: true,
    writable: false,
    enumerable: false,
  });

  return debounced;
}

