const isObj = (v: unknown): v is Record<string, unknown> =>
  v !== null && typeof v === "object" && !Array.isArray(v);

const deepMerge = (t: Record<string, unknown>, s: Record<string, unknown>): Record<string, unknown> => {
  const r = { ...t };
  for (const k in s) {
    r[k] = Array.isArray(r[k]) && Array.isArray(s[k])
      ? [...(r[k] as unknown[]), ...(s[k] as unknown[])]
      : isObj(r[k]) && isObj(s[k])
      ? deepMerge(r[k] as Record<string, unknown>, s[k] as Record<string, unknown>)
      : s[k];
  }
  return r;
};

