type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 7 },   // dayOfWeek (0 and 7 both = Sunday)
];

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}]`);
  }
  return value;
}

function parseNumber(str: string, min: number, max: number): number {
  const n = parseInt(str, 10);
  if (isNaN(n) || String(n) !== str.trim()) {
    throw new TypeError(`Invalid number: "${str}"`);
  }
  return clamp(n, min, max);
}

function range(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step value: */n or range/n
  if (segment.includes("/")) {
    const [left, right, ...extra] = segment.split("/");
    if (extra.length > 0 || right === undefined) {
      throw new SyntaxError(`Invalid step expression: "${segment}"`);
    }
    const step = parseInt(right, 10);
    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Invalid step value: "${right}"`);
    }
    let start = min;
    let end = max;
    if (left !== "*") {
      if (left.includes("-")) {
        const [rangeStart, rangeEnd] = left.split("-");
        start = parseNumber(rangeStart, min, max);
        end = parseNumber(rangeEnd, min, max);
        if (start > end) throw new RangeError(`Invalid range: "${left}"`);
      } else {
        start = parseNumber(left, min, max);
      }
    }
    return range(start, end, step);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range expression: "${segment}"`);
    }
    const start = parseNumber(parts[0], min, max);
    const end = parseNumber(parts[1], min, max);
    if (start > end) throw new RangeError(`Start of range must be <= end: "${segment}"`);
    return range(start, end);
  }

  // Plain number
  return [parseNumber(segment, min, max)];
}

function parseField(field: string, config: FieldConfig): number[] {
  const segments = field.split(",");
  if (segments.length === 0) {
    throw new SyntaxError(`Empty field`);
  }
  const values = new Set<number>();
  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) throw new SyntaxError(`Empty segment in field: "${field}"`);
    for (const v of parseSegment(trimmed, config)) {
      // Normalize dayOfWeek: treat 7 as 0 (both = Sunday)
      values.add(v);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
}

function normalizeDayOfWeek(values: number[]): number[] {
  const normalized = new Set<number>();
  for (const v of values) {
    normalized.add(v === 7 ? 0 : v);
  }
  return Array.from(normalized).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  const minute = parseField(minuteField, FIELD_CONFIGS[0]);
  const hour = parseField(hourField, FIELD_CONFIGS[1]);
  const dayOfMonth = parseField(domField, FIELD_CONFIGS[2]);
  const month = parseField(monthField, FIELD_CONFIGS[3]);
  const dayOfWeek = normalizeDayOfWeek(parseField(dowField, { min: 0, max: 7 }));

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

