function parseStrictUnsignedInt(raw: string, label: string): number {
  assertString(raw, label);
  const trimmed = raw.trim();
  if (trimmed.length === 0) {
    throw new TypeError(`${label}: cannot parse integer from empty string`);
  }
  if (!/^\d+$/.test(trimmed)) {
    throw new TypeError(`${label}: "${trimmed}" is not a valid non-negative integer`);
