  const n = parseInt(trimmed, 10);
  if (!Number.isFinite(n) || !Number.isInteger(n)) {
    throw new TypeError(`${label}: "${trimmed}" did not produce a finite integer (got ${n})`);
  }
  return n;
}

function validateBounds(value: number, range: FieldRange, fieldName: string): void {
  if (value < range.min || value > range.max) {
    throw new RangeError(
      `Field "${fieldName}": value ${value} is outside valid range [${range.min}, ${range.max}]`
    );
  }
}

function expandValues(start: number, end: number, step: number, range: FieldRange, fieldName: string): number[] {
  if (!Number.isInteger(start) || !Number.isInteger(end) || !Number.isInteger(step)) {
    throw new TypeError(`Field "${fieldName}": start, end, and step must all be integers`);
  }
  if (step < 1) {
    throw new RangeError(`Field "${fieldName}": step must be >= 1, got ${step}`);
  }
  if (start > end) {
    throw new RangeError(
      `Field "${fieldName}": range start ${start} must not exceed range end ${end}`
    );
  }
  validateBounds(start, range, fieldName);
  validateBounds(end, range, fieldName);

  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
    if (result.length > 10_000) {
      throw new RangeError(
        `Field "${fieldName}": expansion exceeded safety limit of 10,000 values — possible infinite loop`
      );
