  }
  return result;
}

function parseSegment(token: string, fieldName: string, range: FieldRange): number[] {
  assertString(token, `parseSegment(${fieldName})`);
  const t = token.trim();
  if (t.length === 0) {
    throw new TypeError(`Field "${fieldName}": segment cannot be empty`);
