      }
      const start = parseStrictUnsignedInt(dashParts[0], `field "${fieldName}" range start`);
      const end   = parseStrictUnsignedInt(dashParts[1], `field "${fieldName}" range end`);
      return expandValues(start, end, step, range, fieldName);
    }

    throw new TypeError(
      `Field "${fieldName}": step base must be "*" or a range like "a-b", got "${base}"`
    );
  }

  if (t === '*') {
    return expandValues(range.min, range.max, 1, range, fieldName);
  }

  if (t.includes('-')) {
    const dashParts = t.split('-');
    if (dashParts.length !== 2 || dashParts[0].length === 0 || dashParts[1].length === 0) {
      throw new TypeError(`Field "${fieldName}": malformed range "${t}"`);
    }
    const start = parseStrictUnsignedInt(dashParts[0], `field "${fieldName}" range start`);
    const end   = parseStrictUnsignedInt(dashParts[1], `field "${fieldName}" range end`);
    return expandValues(start, end, 1, range, fieldName);
  }

  if (!/^\d+$/.test(t)) {
    throw new TypeError(
      `Field "${fieldName}": unrecognized token "${t}" — expected number, "*", "a-b", "*/n", or "a-b/n"`
    );
  }
  const value = parseStrictUnsignedInt(t, `field "${fieldName}" single value`);
  validateBounds(value, range, fieldName);
  return [value];
}

function parseField(raw: string, fieldName: string, range: FieldRange): number[] {
  assertString(raw, `parseField(${fieldName})`);
  if (range === null || range === undefined) {
    throw new TypeError(`parseField: no range provided for field "${fieldName}"`);
  }

  const trimmed = raw.trim();
  if (trimmed.length === 0) {
    throw new TypeError(`Field "${fieldName}": raw field string cannot be empty`);
  }

  const segments = trimmed.split(',');
  if (segments.length === 0) {
    throw new TypeError(`Field "${fieldName}": splitting by comma produced no segments`);
  }

  const seen = new Set<number>();

  for (let s = 0; s < segments.length; s++) {
    const seg = segments[s];
    if (seg === undefined || seg === null) {
      throw new TypeError(`Field "${fieldName}": segment at index ${s} is null/undefined`);
    }
    const trimmedSeg = seg.trim();
    if (trimmedSeg.length === 0) {
      throw new TypeError(
        `Field "${fieldName}": empty segment at index ${s} in expression "${trimmed}"`
      );
    }
    const values = parseSegment(trimmedSeg, fieldName, range);
    if (!Array.isArray(values)) {
      throw new TypeError(`Field "${fieldName}": parseSegment returned non-array for segment "${trimmedSeg}"`);
    }
    for (const v of values) {
      if (!Number.isInteger(v)) {
        throw new TypeError(`Field "${fieldName}": non-integer value ${v} produced from segment "${trimmedSeg}"`);
      }
      seen.add(v);
    }
  }

  if (seen.size === 0) {
    throw new RangeError(`Field "${fieldName}": expression "${trimmed}" produced no valid values`);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (expression === null || expression === undefined) {
    throw new TypeError(`parseCron: expression must be a non-null string, got ${expression}`);
  }
  if (typeof expression !== 'string') {
    throw new TypeError(`parseCron: expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new TypeError('parseCron: expression must not be blank');
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new TypeError(
      `parseCron: cron expression must have exactly 5 fields, got ${fields.length} in "${trimmed}"`
    );
  }

  const result = Object.create(null) as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    if (fieldName === undefined || fieldName === null) {
      throw new TypeError(`parseCron: internal error — FIELD_ORDER[${i}] is ${fieldName}`);
    }

    const range = FIELD_RANGES[fieldName];
    if (range === undefined || range === null) {
      throw new TypeError(`parseCron: internal error — no range entry for field "${fieldName}"`);
    }

    const rawField = fields[i];
    if (rawField === undefined || rawField === null) {
      throw new TypeError(`parseCron: internal error — fields[${i}] is ${rawField}`);
    }

    const values = parseField(rawField, fieldName, range);

    if (!Array.isArray(values) || values.length === 0) {
      throw new TypeError(
        `parseCron: field "${fieldName}" yielded an empty or non-array result`
      );
    }

    result[fieldName] = values;
  }

  const requiredKeys: ReadonlyArray<keyof CronFields> = ['minute', 'hour', 'dayOfMonth', 'month', 'dayOfWeek'];
  for (const key of requiredKeys) {
    if (!Object.prototype.hasOwnProperty.call(result, key)) {
      throw new TypeError(`parseCron: result is missing required field "${key}"`);
    }
  }

  return result;
}

