type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<F extends AnyFunction> = {
  (...args: Parameters<F>): void;
  cancel: () => void;
  flush: () => void;
};

const debounce = <F extends AnyFunction>(
  fn: F,
  delayMs: number
): DebouncedFunction<F> => {
  let pendingTimerId: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<F> | null = null;

  const clearPendingTimer = () => {
    if (pendingTimerId !== null) {
      clearTimeout(pendingTimerId);
      pendingTimerId = null;
    }
  };

  const invokePendingWithArgs = (args: Parameters<F>) => {
    clearPendingTimer();
    pendingArgs = null;
    fn(...args);
  };

  const scheduleInvocation = (...args: Parameters<F>): void => {
    clearPendingTimer();
    pendingArgs = args;
    pendingTimerId = setTimeout(() => invokePendingWithArgs(args), delayMs);
  };

  scheduleInvocation.cancel = () => {
    clearPendingTimer();
    pendingArgs = null;
  };

  scheduleInvocation.flush = () => {
    if (pendingArgs !== null) {
      invokePendingWithArgs(pendingArgs);
    }
  };

  return scheduleInvocation;
};

export default debounce;
