const flattenObject = (obj: Record<string, unknown>, prefix = ""): Record<string, unknown> =>
  Object.entries(obj).reduce((acc, [k, v]) => {
    const key = prefix ? `${prefix}.${k}` : k;
    return v && typeof v === "object" && !Array.isArray(v)
      ? { ...acc, ...flattenObject(v as Record<string, unknown>, key) }
      : { ...acc, [key]: v };
  }, {});

export default flattenObject;
// @stance: minimal

type Debounced<T extends (...args: any[]) => any> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: any[]) => any>(fn: T, delay: number): Debounced<T> {
  let timer: ReturnType<typeof setTimeout> | null = null;
  let pending: Parameters<T> | null = null;

  const d = (...args: Parameters<T>) => {
    pending = args;
    if (timer) clearTimeout(timer);
    timer = setTimeout(() => {
      fn(...pending!);
      timer = null;
      pending = null;
    }, delay);
  };

  d.cancel = () => {
    if (timer) clearTimeout(timer);
    timer = null;
    pending = null;
  };

  d.flush = () => {
    if (timer && pending) {
      clearTimeout(timer);
      fn(...pending);
      timer = null;
      pending = null;
    }
  };

  return d;
} // @stance: minimal

// Valid ranges for each cron field — these are the boundaries we enforce.
// Month is 1-12 (not 0-11), dayOfWeek is 0-6 (Sun=0) or 1-7 depending on
// convention. We use 0-6 here to match most Unix cron implementations.
const FIELD_RANGES: Record<string, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

// Field names in positional order — cron fields are order-dependent.
const FIELD_NAMES = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

type FieldName = typeof FIELD_NAMES[number];

export type ParsedCron = Record<FieldName, number[]>;

// ─── helpers ────────────────────────────────────────────────────────────────

/**
 * Build a contiguous array of integers from `start` to `end`, inclusive.
 * Step defaults to 1, but can be larger for */N expressions.
 */
function buildRange(start: number, end: number, step: number = 1): number[] {
  // Guard against infinite loops from a bad step value.
  if (step < 1) throw new RangeError(`Step must be >= 1, got ${step}`);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

/**
 * Clamp and validate a single numeric value against a field's allowed range.
 * Throws clearly so callers know exactly what went wrong — easier to debug
 * than a silent NaN or out-of-range value slipping through.
 */
function assertInRange(value: number, field: string): void {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range for field "${field}" (${min}–${max})`
    );
  }
}

// ─── per-token parser ────────────────────────────────────────────────────────

/**
 * Parse one cron token (e.g. "*", "5", "1-5", "*/15", "1,3,5") into an
 * array of concrete integer values.  Comma lists are split here and each
 * sub-token is handled recursively, keeping the logic flat and readable.
 */
function parseToken(token: string, field: string): number[] {
  const { min, max } = FIELD_RANGES[field];

  // ── comma list: "1,3,5" → parse each part individually then merge ──
  if (token.includes(",")) {
    const parts = token.split(",");
    // Use a Set to deduplicate in case the user writes "1,1,3".
    const seen = new Set<number>();
    for (const part of parts) {
      for (const v of parseToken(part.trim(), field)) {
        seen.add(v);
      }
    }
    // Return sorted so callers get a predictable order.
    return Array.from(seen).sort((a, b) => a - b);
  }

  // ── step value: "*/15" or "0-30/5" ──
  if (token.includes("/")) {
    const [rangePart, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);

    // A step of 0 would loop forever; reject it early.
    if (isNaN(step) || step < 1) {
      throw new RangeError(`Invalid step "${stepStr}" in token "${token}"`);
    }

    // The left side of "/" can itself be a range or just "*".
    let rangeStart = min;
    let rangeEnd   = max;

    if (rangePart !== "*") {
      // Allow "start-end/step" syntax.
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(n => parseInt(n, 10));
        assertInRange(s, field);
        assertInRange(e, field);
        rangeStart = s;
        rangeEnd   = e;
      } else {
        // "5/15" means "starting at 5, every 15 up to max".
        rangeStart = parseInt(rangePart, 10);
        assertInRange(rangeStart, field);
      }
    }

    return buildRange(rangeStart, rangeEnd, step);
  }

  // ── plain range: "9-17" ──
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new TypeError(`Invalid range token "${token}" for field "${field}"`);
    }

    assertInRange(start, field);
    assertInRange(end,   field);

    // Allow reverse ranges to fail loudly — silent reversal would hide bugs.
    if (start > end) {
      throw new RangeError(
        `Range start (${start}) must be <= end (${end}) in token "${token}"`
      );
    }

    return buildRange(start, end);
  }

  // ── wildcard: "*" expands to every valid value in the field ──
  if (token === "*") {
    return buildRange(min, max);
  }

  // ── plain number: "5" ──
  const num = parseInt(token, 10);
  if (isNaN(num)) {
    throw new TypeError(`Unrecognised cron token "${token}" for field "${field}"`);
  }
  assertInRange(num, field);
  return [num];
}

// ─── main export ─────────────────────────────────────────────────────────────

/**
 * Parse a 5-field cron expression string into concrete value arrays.
 *
 * Throws if the expression doesn't have exactly 5 fields or if any value
 * falls outside the accepted range for its field.
 *
 * @example
 *   parseCron("*/15 9-17 * * 1-5")
 *   // { minute:[0,15,30,45], hour:[9..17], dayOfMonth:[1..31],
 *   //   month:[1..12], dayOfWeek:[1,2,3,4,5] }
 */
export default function parseCron(expression: string): ParsedCron {
  // Normalise whitespace before splitting so "*/15  9-17" still works.
  const tokens = expression.trim().split(/\s+/);

  if (tokens.length !== 5) {
    throw new TypeError(
      `Cron expression must have exactly 5 fields, got ${tokens.length}: "${expression}"`
    );
  }

  // Build the result object field by field.  Using `reduce` here would be
  // clever but harder to step through at 3am — explicit loop wins.
  const result = {} as ParsedCron;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const field = FIELD_NAMES[i];
    const token = tokens[i];
    result[field] = parseToken(token, field);
  }

  return result;
}
