type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || value === undefined) return false;
  if (typeof value !== "object") return false;
  if (Array.isArray(value)) return false;

  const proto = Object.getPrototypeOf(value);
  if (proto === null) return true;
  if (proto !== Object.prototype) return false;

  return true;
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (target === null && source === null) return null;
  if (target === undefined && source === undefined) return undefined;

  if (typeof target !== "object" && typeof source !== "object") {
    if (source === undefined) return target;
    return source;
  }

  if (Array.isArray(target) && Array.isArray(source)) {
    const targetArr = target as unknown[];
    const sourceArr = source as unknown[];

    if (!Array.isArray(targetArr) || !Array.isArray(sourceArr)) {
      throw new TypeError(
        `[deepMerge] Array coercion failed — this should never happen`
      );
    }

    return [...targetArr, ...sourceArr];
  }

  if (Array.isArray(target) !== Array.isArray(source)) {
    if (source === undefined) return target;
    return source;
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = Object.create(null);

    const targetKeys = Object.keys(target);
    const sourceKeys = Object.keys(source);

    for (const key of targetKeys) {
      if (
        typeof key !== "string" ||
        key === "__proto__" ||
        key === "constructor" ||
        key === "prototype"
      ) {
        continue;
      }

      result[key] = target[key];
    }

    for (const key of sourceKeys) {
      if (
        typeof key !== "string" ||
        key === "__proto__" ||
        key === "constructor" ||
        key === "prototype"
      ) {
        continue;
      }

      const sourceVal = source[key];
      const targetVal = result[key];

      if (sourceVal === undefined) {
        continue;
      }

      result[key] = deepMerge(targetVal, sourceVal);
    }

    return result;
  }

  if (source === undefined) return target;
  if (target === undefined) return source;

  return source;
}

export default function safeMerge(
  target: unknown,
  source: unknown
): PlainObject {
  if (target === null || target === undefined) {
    throw new TypeError(
      `[deepMerge] 'target' must be a non-null plain object, got: ${
        target === null ? "null" : "undefined"
      }`
    );
  }

  if (source === null || source === undefined) {
    throw new TypeError(
      `[deepMerge] 'source' must be a non-null plain object, got: ${
        source === null ? "null" : "undefined"
      }`
    );
  }

  if (!isPlainObject(target)) {
    throw new TypeError(
      `[deepMerge] 'target' must be a plain object, got: ${
        Array.isArray(target) ? "array" : typeof target
      }`
    );
  }

  if (!isPlainObject(source)) {
    throw new TypeError(
      `[deepMerge] 'source' must be a plain object, got: ${
        Array.isArray(source) ? "array" : typeof source
      }`
    );
  }

  const merged = deepMerge(target, source);

  if (!isPlainObject(merged)) {
    throw new TypeError(
      `[deepMerge] Internal error: merge result is not a plain object — got: ${typeof merged}`
    );
  }

  return merged;
}
