type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<F extends AnyFunction> = {
  (...args: Parameters<F>): void;
  cancel: () => void;
  flush: () => void;
};

const debounce = <F extends AnyFunction>(
  fn: F,
  delayMs: number
): DebouncedFunction<F> => {
  let pendingTimer: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<F> | null = null;

  const clearPending = () => {
    if (pendingTimer !== null) {
      clearTimeout(pendingTimer);
      pendingTimer = null;
    }
  };

  const invokePending = () => {
    if (pendingArgs !== null) {
      const argsToApply = pendingArgs;
      pendingArgs = null;
      fn(...argsToApply);
    }
  };

  const scheduleInvocation = (args: Parameters<F>) => {
    clearPending();
    pendingArgs = args;
    pendingTimer = setTimeout(() => {
      pendingTimer = null;
      invokePending();
    }, delayMs);
  };

  const debounced = (...args: Parameters<F>): void => {
    scheduleInvocation(args);
  };

  debounced.cancel = () => {
    clearPending();
    pendingArgs = null;
  };

  debounced.flush = () => {
    clearPending();
    invokePending();
  };

  return debounced;
};

export default debounce;
